INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('ab74fdde-2b63-5b69-a061-16f36729f6b1', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'alarm', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/əˈlɑːm/', 'audio/alarm.mp3', 'A summons to arms, as on the approach of an enemy.', 'The clock radio is a friendlier version of the cold alarm by the bedside.', 'Home & Living', 'báo động', 'Một lời kêu gọi vũ trang, như khi kẻ thù đến gần.', 'Đồng hồ radio là một phiên bản thân thiện hơn của chuông báo thức lạnh lẽo bên cạnh giường.'),
    ('c858497e-8b66-521c-9c84-fcee8719c4ea', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'attach', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/əˈtætʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/attach-uk.mp3', 'To fasten, to join to (literally and figuratively).', 'An officer is attached to a certain regiment, company, or ship.', 'Home & Living', 'gắn, đính kèm', 'Buộc chặt, nối vào (theo nghĩa đen và nghĩa bóng).', 'Một sĩ quan được gắn với một trung đoàn, đại đội hoặc con tàu nhất định.'),
    ('da60f538-2de1-5065-af85-6981c391ff5e', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'bell', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/bɛl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bell-us.mp3', 'A percussive instrument made of metal or other hard material, typically but not always in the shape of an inverted cup with a flared rim, which resonates when struck.', 'I’ll give you a bell later.', 'Home & Living', 'chuông', 'Nhạc cụ gõ làm bằng kim loại hoặc vật liệu cứng khác, thường nhưng không phải lúc nào cũng có hình dạng một chiếc cốc úp ngược với vành loe, phát ra âm thanh khi bị gõ.', 'Tôi sẽ gọi điện cho anh sau.'),
    ('249914a8-c1fd-5ef1-ac0e-9ed23d3b140a', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'block', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/blɒk/', 'audio/block.mp3', 'A substantial, often approximately cuboid, piece of any substance.', 'a block of ice', 'Home & Living', 'khối', 'Một mảnh lớn, thường có dạng gần như hình khối, của bất kỳ chất liệu nào.', 'một khối băng'),
    ('24c0a186-0f6f-5e27-8c69-fbce00ac3238', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'ceiling', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈsiːlɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ceiling-uk.mp3', 'To line or finish (a surface, such as a wall), with plaster, stucco, thin boards, or similar.', 'the dining room had an ornate ceiling', 'Home & Living', 'trần nhà', 'Để lót hoặc hoàn thiện (một bề mặt, chẳng hạn như tường), bằng thạch cao, vữa, ván mỏng, hoặc tương tự.', 'phòng ăn có một trần nhà được trang trí công phu'),
    ('34b50c33-fa82-51d1-9ded-506285ba2c6b', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'chain', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈt͡ʃeɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chain-us.mp3', 'A series of interconnected rings or links usually made of metal.', 'He wore a gold chain around the neck.', 'Home & Living', 'dây chuyền', 'Một chuỗi các vòng hoặc mắt xích được kết nối với nhau, thường làm bằng kim loại.', 'Anh ta đeo một sợi dây chuyền vàng quanh cổ.'),
    ('ed7665d6-e556-56ce-8a2b-8ac0f961d690', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'chest', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/t͡ʃɛst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chest-uk.mp3', 'A box, now usually a large strong box with a secure convex lid.', 'The clothes are kept in a chest.', 'Home & Living', 'rương', 'Một cái hộp, nay thường là một chiếc hộp lớn chắc chắn có nắp lồi an toàn.', 'Quần áo được cất trong một chiếc rương.'),
    ('fb55428a-c568-5751-8b46-23c579c63b02', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'cloth', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/klɑθ/', 'audio/cloth.mp3', 'A woven fabric such as used in dressing, decorating, cleaning or other practical use.', 'He is a respected man of the cloth.', 'Home & Living', 'vải', 'Một loại vải dệt được sử dụng trong việc mặc quần áo, trang trí, làm sạch hoặc các mục đích thực tế khác.', 'Ông ấy là một mục sư được kính trọng.'),
    ('11a4c3c1-9d1f-54f1-bbd4-29cdba362fb5', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'convenient', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/kənˈviːniənt/', 'audio/convenient.mp3', 'Serving to reduce a difficulty, or accessible with minimum difficulty; expedient.', 'Fast food might be convenient, but it''s also very unhealthy.', 'Home & Living', 'tiện lợi', 'Phục vụ để giảm bớt khó khăn, hoặc có thể tiếp cận với khó khăn tối thiểu; thuận tiện.', 'Đồ ăn nhanh có thể tiện lợi, nhưng nó cũng rất không tốt cho sức khỏe.'),
    ('eb83f759-403b-5728-9640-dd67ae43305b', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'cottage', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkɒtɪdʒ/', 'audio/cottage.mp3', 'A small house.', 'Most cottages in the area were larger and more elaborate than my home.', 'Home & Living', 'nhà tranh', 'Một ngôi nhà nhỏ.', 'Hầu hết các ngôi nhà tranh trong khu vực đều lớn hơn và công phu hơn ngôi nhà của tôi.'),
    ('44216d18-9b5e-5507-b01c-b8b11e9841a8', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'covered', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈkʌvə(ɹ)d/', 'https://api.dictionaryapi.dev/media/pronunciations/en/covered-us.mp3', 'To place something over or upon, as to conceal or protect.', 'He covered the baby with a blanket.', 'Home & Living', 'được che phủ', 'Đặt thứ gì đó lên trên hoặc lên, để che giấu hoặc bảo vệ.', 'Anh ấy đắp chăn cho em bé.'),
    ('93753e23-bda8-5260-a475-74cdaaf776f7', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'curtain', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkɜːtn̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/curtain-uk.mp3', 'A piece of cloth covering a window, bed, etc. to offer privacy and keep out light.', 'He took so long to shave his head that we arrived 45 minutes after curtain and were denied late entry.', 'Home & Living', 'rèm cửa', 'Một mảnh vải che cửa sổ, giường, v.v. để tạo sự riêng tư và che ánh sáng.', 'Anh ấy cạo đầu lâu đến nỗi chúng tôi đến 45 phút sau khi màn kéo lên và bị từ chối vào muộn.'),
    ('38b24f55-16c1-51a1-817b-fb8d4afda0cc', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'decorate', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ˈdɛkəɹeɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/decorate-us.mp3', 'To furnish with decorations.', 'We decorated the Christmas tree with tinsel and baubles.', 'Home & Living', 'trang trí', 'Trang bị bằng đồ trang trí.', 'Chúng tôi trang trí cây thông Noel bằng kim tuyến và quả cầu.'),
    ('7b6928ab-e702-50b7-9632-c38c6b354a56', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'entrance', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɛn.tɹəns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/entrance-1-uk.mp3', 'The action of entering, or going in.', 'Her entrance attracted no attention whatsoever.', 'Home & Living', 'lối vào', 'Hành động đi vào, hoặc bước vào.', 'Sự xuất hiện của cô ấy không thu hút chút chú ý nào.'),
    ('74e1a0f3-961d-502b-95e1-6a66f3930f43', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'entry', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɛntɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/entry.mp3', 'The act of entering.', 'Children are allowed entry only if accompanied by an adult.', 'Home & Living', 'sự vào', 'Hành động đi vào.', 'Trẻ em chỉ được phép vào nếu có người lớn đi cùng.'),
    ('a37f0ed8-655a-57f1-9b02-b2a51d4d928f', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'fasten', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ˈfɑːsn̩/', 'audio/fasten.mp3', 'To attach or connect in a secure manner.', 'Can you fasten these boards together with some nails?', 'Home & Living', 'buộc chặt, cố định', 'Gắn hoặc kết nối một cách chắc chắn.', 'Bạn có thể đóng chặt những tấm ván này lại với nhau bằng một vài cái đinh không?'),
    ('c924af52-1ef3-5cf6-8681-4111f71b621a', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'fixed', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/fɪkst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fixed-us.mp3', 'To pierce; now generally replaced by transfix.', 'A dab of chewing gum will fix your note to the bulletin board.', 'Home & Living', 'cố định', 'Để xuyên qua; giờ thường được thay thế bằng từ ''xuyên qua''.', 'Một chút kẹo cao su sẽ giúp cố định ghi chú của bạn vào bảng thông báo.'),
    ('9ba82613-8e6f-50e2-ada7-8c29fe5d0644', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'fold', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/fəʊld/', 'audio/fold.mp3', 'An act of folding.', 'After two reraises in quick succession, John realised his best option was probably a fold.', 'Home & Living', 'gấp', 'Hành động gấp.', 'Sau hai lần tăng cược liên tiếp, John nhận ra lựa chọn tốt nhất của anh ấy có lẽ là bỏ bài.'),
    ('ca4bd7ba-eea4-5b70-a52f-dfeff86534f8', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'frame', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/fɹeɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/frame-us.mp3', 'The structural elements of a building or other constructed object.', 'Now that the frame is complete, we can start on the walls.', 'Home & Living', 'khung', 'Các yếu tố kết cấu của một tòa nhà hoặc đối tượng xây dựng khác.', 'Bây giờ khung đã hoàn thành, chúng ta có thể bắt đầu làm tường.'),
    ('d9a481f6-b236-5cb8-9f29-ac1eceea3ae9', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'garage', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɡəˈɹɑː(d)ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/garage-au.mp3', 'A building (or section of a building) used to store a car or cars, tools and other miscellaneous items.', 'We garaged the convertible during the monsoon months.', 'Home & Living', 'nhà để xe', 'Một tòa nhà (hoặc phần của tòa nhà) dùng để chứa ô tô, công cụ và các vật dụng linh tinh khác.', 'Chúng tôi để chiếc xe mui trần trong nhà xe suốt những tháng mùa mưa.'),
    ('5b70ed85-71f9-524f-a504-586f9eab53c7', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'hang', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '[heɪŋ]', 'audio/hang.mp3', 'The way in which something hangs.', 'This skirt has a nice hang.', 'Home & Living', 'treo', 'Cách mà một thứ gì đó được treo.', 'Chiếc váy này có độ rủ đẹp.'),
    ('81f480ec-5063-5a94-9f85-967b5ec29cc6', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'heating', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈhiːtɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/heating-us.mp3', 'To cause an increase in temperature of (an object or space); to cause to become hot (often with "up").', 'I''ll heat up the water.', 'Home & Living', 'sự sưởi ấm', 'Gây ra sự gia tăng nhiệt độ của (một vật thể hoặc không gian); khiến trở nên nóng (thường đi với "up").', 'Tôi sẽ đun nóng nước lên.'),
    ('af7bb96a-8243-5c26-ba06-6b29f7a01fdf', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'indoor', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈɪndɔː/', 'audio/indoor.mp3', 'Situated in, or designed to be used in, or carried on within, the interior of a building.', 'These fireworks are not for indoor use!', 'Home & Living', 'trong nhà', 'Nằm trong, hoặc được thiết kế để sử dụng trong, hoặc được tiến hành bên trong, nội thất của một tòa nhà.', 'Những pháo hoa này không dùng trong nhà!'),
    ('e855066a-b739-54ea-bf6d-8e7798e011b7', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'indoors', 'B1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B1"}]'::jsonb, '/ɪnˈdɔːz/', 'audio/indoors.mp3', 'The interior of a building; the space inside buildings generally.', 'I prefer the indoors to the outdoors.', 'Home & Living', 'trong nhà', 'Phần bên trong của một tòa nhà; không gian bên trong các tòa nhà nói chung.', 'Tôi thích ở trong nhà hơn ngoài trời.'),
    ('da48ec05-b05f-5666-b784-4dad8e6af2bb', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'iron', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈaɪən/', 'audio/iron.mp3', 'A common, inexpensive metal, silvery grey when untarnished, that rusts, is attracted by magnets, and is used in making steel.', 'wrought iron, ductile iron, cast iron, pig iron, gray iron', 'Home & Living', 'bàn là, sắt', 'Một kim loại phổ biến, giá rẻ, màu xám bạc khi chưa bị xỉn màu, dễ gỉ, bị nam châm hút và được dùng để chế tạo thép.', 'sắt rèn, sắt dẻo, gang đúc, gang thô, gang xám'),
    ('abfb9067-ebec-532d-8703-5add63732c90', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'living', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ˈlɪvɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/living-uk.mp3', 'To be alive; to have life.', 'He''s not expected to live for more than a few months.', 'Home & Living', 'cuộc sống', 'Để được sống; để có sự sống.', 'Anh ấy không được kỳ vọng sẽ sống thêm được hơn vài tháng.'),
    ('4160b32a-0dd3-54b1-ba35-fb926b3f6a1b', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'mess', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/mɛs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mess-us.mp3', 'A disagreeable mixture or confusion of things; hence, a situation resulting from blundering or from misunderstanding; disorder.', 'He made a mess of it.', 'Home & Living', 'sự lộn xộn, bừa bộn', 'Một sự pha trộn hoặc hỗn loạn khó chịu của các thứ; do đó, một tình huống phát sinh từ sai lầm hoặc hiểu lầm; sự mất trật tự.', 'Anh ấy đã làm hỏng chuyện.'),
    ('ddb28647-3d5a-5db9-9196-00b30b37f5d3', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'needle', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈniː.dl/', 'audio/needle.mp3', 'A fine, sharp implement usually for piercing such as sewing, or knitting, acupuncture, tattooing, body piercing, medical injections, etc.', 'The seamstress threaded the needle to sew on a button.', 'Home & Living', 'kim', 'Một dụng cụ nhỏ, sắc thường dùng để xuyên qua như may, đan, châm cứu, xăm hình, xỏ khuyên, tiêm thuốc, v.v.', 'Người thợ may xỏ kim để đính cúc.'),
    ('f6a89add-aca4-578a-8dc8-db2fe5ef1392', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'pin', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/pɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pin-ca.mp3', 'A needle without an eye (usually) made of drawn-out steel wire with one end sharpened and the other flattened or rounded into a head, used for fastening.', 'Pull the pin out of the grenade before throwing it at the enemy.', 'Home & Living', 'ghim', 'Một cây kim không có lỗ (thường) làm bằng dây thép kéo dài với một đầu nhọn và đầu kia dẹt hoặc tròn thành đầu, dùng để cố định.', 'Kéo chốt ra khỏi lựu đạn trước khi ném nó vào kẻ thù.'),
    ('6eb6a211-51d6-5f64-a402-d3a11220a2e1', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'pipe', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/paɪp/', 'audio/pipe.mp3', 'Meanings relating to a wind instrument.', 'to pipe flowers on to a cupcake', 'Home & Living', 'ống', 'Ý nghĩa liên quan đến nhạc cụ hơi.', 'bắt kem hoa lên bánh cupcake'),
    ('45bd5ac7-7d14-5c9b-961a-e19c125df69d', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'pot', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pɒt/', 'audio/pot.mp3', 'A flat-bottomed vessel (usually metal) used for cooking food.', 'After his arrest, his prospects went to pot.', 'Home & Living', 'nồi', 'Một vật đựng đáy phẳng (thường bằng kim loại) dùng để nấu thức ăn.', 'Sau khi bị bắt, triển vọng của anh ta tan thành mây khói.'),
    ('364208c8-30d0-5ce4-bd4e-8d737f03b539', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'powder', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpaʊ.də(ɹ)/', 'audio/powder.mp3', 'The fine particles which are the result of reducing dry substance by pounding, grinding, or triturating, or the result of decay; dust.', 'to powder one''s hair', 'Home & Living', 'bột', 'Các hạt mịn là kết quả của việc nghiền nhỏ chất khô bằng cách đập, xay, hoặc nghiền, hoặc kết quả của sự phân hủy; bụi.', 'rắc bột lên tóc'),
    ('24382fbd-43c9-586d-96e8-1e21aae1af7f', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'servant', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈsɜːvənt/', 'audio/servant.mp3', 'One who is hired to perform regular household or other duties, and receives compensation. As opposed to a slave.', 'There are three servants in the household, the butler and two maids.', 'Home & Living', 'người hầu', 'Người được thuê để thực hiện các công việc gia đình thường xuyên hoặc các nhiệm vụ khác, và nhận được thù lao. Trái ngược với nô lệ.', 'Có ba người hầu trong gia đình, quản gia và hai người hầu gái.'),
    ('84504955-a0f2-5d5d-8354-66b55d96997b', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'setting', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈsɛtɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/setting-us.mp3', 'To put (something) down, to rest.', 'Set the tray there.', 'Home & Living', 'đặt xuống', 'Đặt (cái gì đó) xuống, để nghỉ ngơi.', 'Đặt khay ở đó.'),
    ('265f1a02-0c52-593e-b00f-b69964bd4269', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'shelf', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ʃɛlf/', 'audio/shelf.mp3', 'A flat, rigid structure, fixed at right angles to a wall or forming a part of a cabinet, desk etc., and used to support, store or display objects.', 'a shelf of videos', 'Home & Living', 'kệ', 'Một cấu trúc phẳng, cứng, được cố định vuông góc với tường hoặc tạo thành một phần của tủ, bàn làm việc, v.v., và được sử dụng để hỗ trợ, lưu trữ hoặc trưng bày đồ vật.', 'một kệ video'),
    ('2fc36dcd-a1ef-5f5a-ab82-ec585096305f', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'sink', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/sɪŋk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sink-uk.mp3', 'A basin used for holding water for washing.', 'Jones has a two-seamer with heavy sink.', 'Home & Living', 'bồn rửa', 'Một bồn chứa nước dùng để rửa.', 'Jones có một cú ném hai đường may với độ xoáy chìm mạnh.'),
    ('44c4a81b-8ad0-5325-818b-ee767021bc8e', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'string', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/stɹɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/string-us.mp3', 'A building, wing or dependency set apart and adapted for lodging and feeding (and training) animals with hoofs, especially horses.', 'There were stalls for fourteen horses in the squire''s stables.', 'Home & Living', 'chuồng ngựa', 'Một tòa nhà, dãy nhà hoặc công trình phụ được tách riêng và cải tạo để làm chỗ ở và cho ăn (và huấn luyện) động vật có móng, đặc biệt là ngựa.', 'Có những chuồng cho mười bốn con ngựa trong trại ngựa của điền chủ.'),
    ('70b46f45-c42e-59ba-b00a-a6fca0668385', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'stuff', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/stʌf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stuff-au.mp3', 'Miscellaneous items or objects; (with possessive) personal effects.', 'What is all that stuff on your bedroom floor? He didn''t want his pockets to bulge so he was walking around with all his stuff in his hands.', 'Home & Living', 'đồ đạc', 'Các vật phẩm hoặc đồ vật linh tinh; (với sở hữu cách) đồ dùng cá nhân.', 'Tất cả những thứ đó trên sàn phòng ngủ của bạn là gì? Anh ấy không muốn túi quần phồng lên nên anh ấy đi loanh quanh với tất cả đồ đạc trên tay.'),
    ('60f64787-d6e8-5a09-8479-bbdf007c416e', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'tape', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/teɪ̯p/', 'audio/tape.mp3', 'Flexible material in a roll with a sticky surface on one or both sides; adhesive tape.', 'Hand me some tape. I need to fix a tear in this paper.', 'Home & Living', 'băng dính', 'Vật liệu dẻo cuộn tròn có bề mặt dính ở một hoặc cả hai mặt; băng dính.', 'Đưa tôi ít băng dính. Tôi cần sửa chỗ rách trên tờ giấy này.'),
    ('4f700833-8bf6-5509-aca2-79b56e1bc269', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'tin', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/tɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tin-uk.mp3', 'A malleable, ductile, metallic element, resistant to corrosion, with atomic number 50 and symbol Sn.', 'muffin tin', 'Home & Living', 'thiếc, hộp thiếc', 'Một nguyên tố kim loại dễ uốn, dễ kéo dài, chống ăn mòn, với số nguyên tử 50 và ký hiệu Sn.', 'khuôn nướng muffin'),
    ('e7b356f1-8cc8-5513-a466-0e48137f4368', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'tube', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/tjuːb/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tube-au.mp3', 'Anything that is hollow and cylindrical in shape.', 'A tube of toothpaste.', 'Home & Living', 'ống, tuýp', 'Bất cứ thứ gì rỗng và có hình trụ.', 'Một tuýp kem đánh răng.'),
    ('feea489e-7409-57e2-9cca-6f89773ad246', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'neighbourhood', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, NULL, 'audio/neighbourhood.mp3', 'The quality of being a neighbor, of living nearby, next to each-other; proximity.', 'Our neighborhood was our only reason to exchange hollow greetings.', 'Home & Living', 'khu phố', 'Chất lượng của việc là hàng xóm, sống gần nhau, cạnh nhau; sự gần gũi.', 'Khu phố của chúng tôi là lý do duy nhất để chúng tôi trao đổi những lời chào hỏi xã giao.'),
    ('3f981a3b-1dfe-5281-947d-30968b539dc8', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'outdoors', 'B1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B1"}]'::jsonb, NULL, 'audio/outdoors.mp3', '(often preceded by "the") The environment outside of enclosed structures.', 'She loves the outdoors.', 'Home & Living', 'ngoài trời', '(thường đi trước bởi "the") Môi trường bên ngoài các công trình khép kín.', 'Cô ấy yêu thích không gian ngoài trời.'),
    ('defea0d1-5c70-5202-b365-5381c5dcb169', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'container', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/kənˈteɪnə/', 'audio/container.mp3', 'Someone who contains; something that contains.', NULL, 'Home & Living', 'vật chứa', 'Người chứa đựng; thứ gì đó chứa đựng.', NULL),
    ('9b674aa5-4ce6-5be9-96be-7cc64da05a7e', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'cotton', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkɒt.n̩/', 'audio/cotton.mp3', 'Gossypium, a genus of plant used as a source of cotton fiber.', NULL, 'Home & Living', 'bông', 'Gossypium, một chi thực vật được sử dụng làm nguồn sợi bông.', NULL),
    ('2cd4a637-19e9-5683-a8e1-bc800a1d9394', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'fence', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/fɛns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fence-us.mp3', 'A thin artificial barrier that separates two pieces of land or a house perimeter.', NULL, 'Home & Living', 'hàng rào', 'Một rào chắn nhân tạo mỏng ngăn cách hai mảnh đất hoặc chu vi nhà.', NULL),
    ('3197fe61-1ac6-56d0-8660-7ce817e5ec00', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'luxury', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈlʌk.ʃə.ɹi/', 'audio/luxury.mp3', 'Very wealthy and comfortable surroundings.', NULL, 'Home & Living', 'sự xa xỉ', 'Môi trường xung quanh rất giàu có và tiện nghi.', NULL),
    ('1750ec09-1582-5790-a4bf-97afd906578d', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'outdoor', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˌaʊtˈdɔː/', 'audio/outdoor.mp3', '(in some African communities) To publicly display a child after it has been named', NULL, 'Home & Living', 'ngoài trời', '(trong một số cộng đồng châu Phi) Trưng bày công khai một đứa trẻ sau khi nó đã được đặt tên', NULL),
    ('782b72d7-d96d-5728-a157-cda4bcd4ce71', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'pan', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pæn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pan-us.mp3', 'A wide, flat receptacle used around the house, especially for cooking.', NULL, 'Home & Living', 'cái chảo', 'Một vật đựng rộng, phẳng được dùng trong nhà, đặc biệt để nấu ăn.', NULL),
    ('18a8ae6f-db65-55e3-94a8-7ba46c033707', 'ac256c47-872e-5a89-b9ed-a011563b8f2c', 'underwear', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈʌndəwɛə/', 'audio/underwear.mp3', 'Clothes worn next to the skin, underneath outer clothing.', NULL, 'Home & Living', 'đồ lót', 'Quần áo mặc sát da, bên dưới quần áo ngoài.', NULL)
