INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('4dcc15fc-3f80-51e3-a3de-0714dc1d63df', '60945554-3420-5dee-bc58-9e959287038d', 'battle', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈbætəl/', 'audio/battle.mp3', 'A contest, a struggle.', 'the battle of life', 'Society & Culture', 'trận chiến, cuộc chiến', 'Một cuộc tranh tài, một cuộc đấu tranh.', 'cuộc chiến của cuộc sống'),
    ('1437cdcf-6b56-5f05-8413-a2ed6705ce21', '60945554-3420-5dee-bc58-9e959287038d', 'border', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈbɔədə/', 'audio/border.mp3', 'The outer edge of something.', 'the borders of the garden', 'Society & Culture', 'biên giới', 'Cạnh ngoài của một thứ gì đó.', 'ranh giới của khu vườn'),
    ('af59cc16-6af7-5a85-b40b-6e8a30d8cf91', '60945554-3420-5dee-bc58-9e959287038d', 'bury', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ˈbʌ.ɹi/', 'audio/bury.mp3', 'A burrow.', 'bury a bone; bury the embers', 'Society & Culture', 'chôn cất', 'Một cái hang.', 'chôn một khúc xương; chôn vùi những đốm than'),
    ('e13e0ca2-d0c2-535f-ae42-d17aa46586ef', '60945554-3420-5dee-bc58-9e959287038d', 'consequence', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkɒnsɪkwɛns/', 'audio/consequence.mp3', 'That which follows something on which it depends; that which is produced by a cause.', 'I''m warning you. If you don''t get me the report on time, there will be consequences.', 'Society & Culture', 'hậu quả', 'Điều theo sau một thứ mà nó phụ thuộc vào; điều được tạo ra bởi một nguyên nhân.', 'Tôi cảnh báo anh. Nếu anh không giao báo cáo cho tôi đúng hạn, sẽ có hậu quả.'),
    ('d3958369-922a-5d2c-b15b-5440b3445363', '60945554-3420-5dee-bc58-9e959287038d', 'custom', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkʌstəm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/custom-us.mp3', 'Frequent repetition of the same behavior; way of behavior common to many; ordinary manner; habitual practice; method of doing, living or behaving.', 'The Ancient Egyptian culture had many distinctive and interesting beliefs and customs.', 'Society & Culture', 'phong tục', 'Sự lặp lại thường xuyên của cùng một hành vi; cách cư xử phổ biến của nhiều người; cách thức thông thường; thói quen thực hành; phương pháp làm, sống hoặc cư xử.', 'Văn hóa Ai Cập cổ đại có nhiều tín ngưỡng và phong tục đặc biệt và thú vị.'),
    ('e13e2dc4-2a32-57bf-923d-3a1c6dd8beb5', '60945554-3420-5dee-bc58-9e959287038d', 'donate', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/dəʊˈneɪt/', 'audio/donate.mp3', 'To make a donation; to give away something of value to support or contribute towards a cause or for the benefit of another.', 'He donated an etching from his own collection to the new art gallery.', 'Society & Culture', 'quyên góp', 'Để quyên góp; cho đi thứ gì đó có giá trị để hỗ trợ hoặc đóng góp cho một mục đích hoặc vì lợi ích của người khác.', 'Ông ấy đã quyên góp một bản khắc từ bộ sưu tập của riêng mình cho phòng trưng bày nghệ thuật mới.'),
    ('a97b0d4f-892c-5d7e-8c43-914b1c0413c9', '60945554-3420-5dee-bc58-9e959287038d', 'enemy', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɛnəmi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/enemy-us.mp3', 'Someone who is hostile to, feels hatred towards, opposes the interests of, or intends injury to someone else.', 'Crush the enemy!', 'Society & Culture', 'kẻ thù', 'Người nào đó thù địch, cảm thấy hận thù, chống lại lợi ích của, hoặc có ý định gây thương tích cho người khác.', 'Tiêu diệt kẻ thù!'),
    ('04a72676-2f7e-5844-a7c3-76ab0ddddbbf', '60945554-3420-5dee-bc58-9e959287038d', 'equal', 'B1', '["adj", "v", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "v", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈiːkwəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/equal-us.mp3', 'A person or thing of equal status to others.', 'This beer has no equal.', 'Society & Culture', 'bằng nhau', 'Một người hoặc vật có địa vị ngang bằng với những người/vật khác.', 'Loại bia này không có đối thủ.'),
    ('288b0bd7-26de-5f01-8a17-156f833f1de8', '60945554-3420-5dee-bc58-9e959287038d', 'familiar', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/fəˈmɪl.i.ə/', 'audio/familiar.mp3', 'An attendant spirit, often in animal or demon form.', 'The witch’s familiar was a black cat.', 'Society & Culture', 'quen thuộc', 'Một linh hồn hầu cận, thường ở dạng động vật hoặc ác quỷ.', 'Vật nuôi quen thuộc của phù thủy là một con mèo đen.'),
    ('4fd1c1bc-1c0c-50b3-9b38-78786b451d3a', '60945554-3420-5dee-bc58-9e959287038d', 'favour', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈfeɪ.və/', 'audio/favour.mp3', 'A kind or helpful deed; an instance of voluntarily assisting (someone).', 'He did me a favor when he took the time to drive me home.', 'Society & Culture', 'ân huệ, giúp đỡ', 'Một hành động tử tế hoặc hữu ích; một trường hợp tự nguyện hỗ trợ (ai đó).', 'Anh ấy đã giúp tôi một ân huệ khi dành thời gian chở tôi về nhà.'),
    ('98fb2f81-e763-5fd1-9205-c25439bab8f6', '60945554-3420-5dee-bc58-9e959287038d', 'flag', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/flæɡ/', 'audio/flag.mp3', 'A piece of cloth, often decorated with an emblem, used as a visual signal or symbol.', 'Please flag down a taxi for me.', 'Society & Culture', 'lá cờ', 'Một mảnh vải, thường được trang trí với biểu tượng, được sử dụng làm tín hiệu hoặc biểu tượng trực quan.', 'Hãy vẫy gọi một chiếc taxi cho tôi.'),
    ('d1735fd5-b20e-5436-9a69-a810706d803f', '60945554-3420-5dee-bc58-9e959287038d', 'folk', 'B1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "adj", "level": "B1"}]'::jsonb, '/fəʊk/', 'audio/folk.mp3', 'A grouping of smaller peoples or tribes as a nation.', 'Young folk, old folk, everybody come, / To our little Sunday School and have a lot of fun.', 'Society & Culture', 'dân gian', 'Một nhóm các dân tộc hoặc bộ lạc nhỏ hơn như một quốc gia.', 'Người trẻ, người già, mọi người đều đến, / Đến trường học Chủ nhật nhỏ của chúng ta và có nhiều niềm vui.'),
    ('164ee1e5-f339-5246-be19-9fce73b95d0c', '60945554-3420-5dee-bc58-9e959287038d', 'generation', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˌd͡ʒɛnəˈɹeɪʃən/', 'audio/generation.mp3', 'The fact of creating something, or bringing something into being; production, creation.', 'This is the book of the generations of Adam - Genesis 5:1', 'Society & Culture', 'thế hệ', 'Việc tạo ra một cái gì đó, hoặc mang một cái gì đó vào sự tồn tại; sự sản xuất, sáng tạo.', 'Đây là sách về các thế hệ của Adam - Sáng thế ký 5:1'),
    ('0a8cfb1b-ac05-57ea-897c-40a2d3ee476d', '60945554-3420-5dee-bc58-9e959287038d', 'gentleman', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈdʒɛn.təl.mən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gentleman-au.mp3', 'A man of gentle but not noble birth, particularly a man of means (originally ownership of property) who does not work for a living but has no official status in a peerage; an armiferous man ranking below a knight.', 'Being a gentleman, Robert was entitled to shove other commoners into the gongpit but he still had to jump out of the way of the knights to avoid the same fate himself.', 'Society & Culture', 'quý ông', 'Một người đàn ông có xuất thân lịch sự nhưng không quý tộc, đặc biệt là một người đàn ông có của cải (ban đầu là sở hữu tài sản) không làm việc để kiếm sống nhưng không có địa vị chính thức trong giới quý tộc; một người đàn ông có huy hiệu xếp dưới hiệp sĩ nhưng trên thường dân.', 'Là một quý ông, Robert có quyền đẩy những thường dân khác vào hố phân nhưng anh ta vẫn phải nhảy ra khỏi đường đi của các hiệp sĩ để tránh số phận tương tự.'),
    ('e3f1736c-8c4b-56a1-993b-0fbb1c3965b8', '60945554-3420-5dee-bc58-9e959287038d', 'ghost', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɡəʊst/', 'audio/ghost.mp3', 'The spirit; the soul of man.', 'Everyone believed that the ghost of an old lady haunted the crypt.', 'Society & Culture', 'ma', 'Linh hồn; linh hồn của con người.', 'Mọi người đều tin rằng hồn ma của một bà lão ám ảnh hầm mộ.'),
    ('2ad4973d-f463-5e66-833f-02e3e0fbdf00', '60945554-3420-5dee-bc58-9e959287038d', 'historic', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/(h)ɪˈstɒɹɪk/', 'audio/historic.mp3', 'A history, a non-fiction account of the past.', 'A historic opportunity', 'Society & Culture', 'mang tính lịch sử', 'Một lịch sử, một tài khoản phi hư cấu về quá khứ.', 'Một cơ hội mang tính lịch sử'),
    ('f9cd7bef-d6fe-5a4c-a011-6d0954961535', '60945554-3420-5dee-bc58-9e959287038d', 'historical', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/hɪˈstɒɹɪkəl/', 'audio/historical.mp3', 'A historical romance.', 'July 4, 1776, is a historic date. A great deal of historical research has been done on the events leading up to that day.', 'Society & Culture', 'thuộc lịch sử', 'Một tiểu thuyết lịch sử lãng mạn.', 'Ngày 4 tháng 7 năm 1776 là một ngày mang tính lịch sử. Rất nhiều nghiên cứu lịch sử đã được thực hiện về các sự kiện dẫn đến ngày đó.'),
    ('8b0158ac-cae0-5efc-b423-8d58bf70e58f', '60945554-3420-5dee-bc58-9e959287038d', 'host', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/həʊst/', 'audio/host.mp3', 'One which receives or entertains a guest, socially, commercially, or officially.', 'A good host is always considerate of the guest’s needs.', 'Society & Culture', 'chủ nhà', 'Người tiếp đón hoặc chiêu đãi một vị khách, về mặt xã hội, thương mại hoặc chính thức.', 'Một chủ nhà tốt luôn quan tâm đến nhu cầu của khách.'),
    ('ea411bfd-4860-560f-90f8-36807ab45c5e', '60945554-3420-5dee-bc58-9e959287038d', 'identity', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/aɪˈdɛntəti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/identity-au.mp3', 'Sameness, identicalness; the quality or fact of (several specified things) being the same.', 'I''ve been through so many changes, I have no sense of identity.', 'Society & Culture', 'bản sắc', 'Sự giống nhau, sự đồng nhất; phẩm chất hoặc thực tế của (một số thứ được chỉ định) là như nhau.', 'Tôi đã trải qua quá nhiều thay đổi, tôi không còn cảm giác về bản sắc của mình nữa.'),
    ('82073298-0201-508b-bbe8-34fb4aa83f1d', '60945554-3420-5dee-bc58-9e959287038d', 'influence', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈɪn.flu.əns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/influence-us.mp3', 'The power to affect, control or manipulate something or someone; the ability to change the development of fluctuating things such as conduct, thoughts or decisions.', 'I have absolutely no influence over him.', 'Society & Culture', 'ảnh hưởng', 'Sức mạnh để tác động, kiểm soát hoặc thao túng điều gì đó hoặc ai đó; khả năng thay đổi sự phát triển của những thứ biến động như hành vi, suy nghĩ hoặc quyết định.', 'Tôi hoàn toàn không có ảnh hưởng gì đến anh ta.'),
    ('8901c1e9-fac7-5590-b68a-6d6ed836b5a5', '60945554-3420-5dee-bc58-9e959287038d', 'nation', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈneɪ.ʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/nation-us.mp3', 'A historically constituted, stable community of people, formed on the basis of a common language, territory, economic life, ethnicity and/or psychological make-up manifested in a common culture.', 'The Kurdish people constitute a nation in the Middle East', 'Society & Culture', 'quốc gia', 'Một cộng đồng người ổn định, được hình thành trong lịch sử, dựa trên cơ sở ngôn ngữ chung, lãnh thổ, đời sống kinh tế, dân tộc và/hoặc cấu trúc tâm lý thể hiện trong một nền văn hóa chung.', 'Người Kurd tạo thành một quốc gia ở Trung Đông'),
    ('48090bdd-beac-57f2-91fe-275df92c08e9', '60945554-3420-5dee-bc58-9e959287038d', 'native', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ˈneɪtɪv/', 'audio/native.mp3', 'An aboriginal inhabitant of a region colonized by English-speaking people; in particular:', 'English is not my native language.', 'Society & Culture', 'bản địa', 'Một cư dân bản địa của một khu vực bị người nói tiếng Anh thuộc địa hóa; cụ thể:', 'Tiếng Anh không phải là ngôn ngữ mẹ đẻ của tôi.'),
    ('23621fc4-bda3-57a2-a7e1-a9f3cbfb450d', '60945554-3420-5dee-bc58-9e959287038d', 'occasion', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/əˈkeɪʒən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/occasion-us.mp3', 'A favorable opportunity; a convenient or timely chance.', 'At this point, she seized the occasion to make her own observation.', 'Society & Culture', 'dịp', 'Một cơ hội thuận lợi; một cơ hội thuận tiện hoặc đúng lúc.', 'Vào thời điểm này, cô ấy nắm lấy dịp để đưa ra nhận xét của riêng mình.'),
    ('3f1d2feb-a0b2-5ce7-aae8-c71d98197120', '60945554-3420-5dee-bc58-9e959287038d', 'peaceful', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈpiːsfəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/peaceful-us.mp3', 'Not at war or disturbed by strife or turmoil.', 'peaceful protest', 'Society & Culture', 'hòa bình, yên bình', 'Không có chiến tranh hoặc bị xáo trộn bởi xung đột hoặc hỗn loạn.', 'biểu tình ôn hòa'),
    ('1b4df4dc-4ae5-5d96-b79b-dfd56e3290d6', '60945554-3420-5dee-bc58-9e959287038d', 'poverty', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɒvəti/', 'audio/poverty.mp3', 'The quality or state of being poor; lack of money', 'poverty of soil', 'Society & Culture', 'nghèo đói', 'Tình trạng hoặc chất lượng của sự nghèo khó; thiếu tiền.', 'sự nghèo nàn của đất'),
    ('922ffc59-65ca-5223-8299-d945733d8b4c', '60945554-3420-5dee-bc58-9e959287038d', 'pray', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/pɹeɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pray-us.mp3', 'To direct words and/or thoughts to God or any higher being, for the sake of adoration, thanks, petition for help, etc.', 'Muslims pray in the direction of Mecca.', 'Society & Culture', 'cầu nguyện', 'Hướng lời nói và/hoặc suy nghĩ đến Chúa hoặc bất kỳ đấng cao hơn nào, vì mục đích tôn thờ, cảm tạ, cầu xin sự giúp đỡ, v.v.', 'Người Hồi giáo cầu nguyện hướng về Mecca.'),
    ('25e7f1cd-a220-50d0-ac7f-4ca9eb869d2c', '60945554-3420-5dee-bc58-9e959287038d', 'prayer', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pɹɛə(ɹ)/', 'audio/prayer.mp3', 'A practice of communicating with one''s God.', 'Through prayer I ask for God''s blessings.', 'Society & Culture', 'lời cầu nguyện', 'Một thực hành giao tiếp với Chúa của một người.', 'Thông qua lời cầu nguyện, tôi cầu xin phước lành của Chúa.'),
    ('357ba6af-7e25-51ca-982d-a7ce8848f37e', '60945554-3420-5dee-bc58-9e959287038d', 'priest', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɹiːst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/priest-uk.mp3', 'A religious clergyman (clergywoman, clergyperson) who is trained to perform services or sacrifices at a church or temple', 'The Israelite priests were descended from Moses'' brother Aaron.', 'Society & Culture', 'linh mục', 'Một giáo sĩ tôn giáo (nữ giáo sĩ, người giáo sĩ) được đào tạo để thực hiện các nghi lễ hoặc hiến tế tại nhà thờ hoặc đền thờ', 'Các thầy tế lễ Israel là con cháu của Aaron, anh trai Moses.'),
    ('f19bec92-c871-5346-846c-69ddd0e4a1be', '60945554-3420-5dee-bc58-9e959287038d', 'prince', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pɹɪns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/prince-us.mp3', 'A (male) ruler, a sovereign; a king, monarch.', 'He is a prince among men.', 'Society & Culture', 'hoàng tử', 'Một người cai trị (nam), một quốc vương; một vị vua, quân chủ.', 'Anh ấy là một hoàng tử giữa những người đàn ông.'),
    ('f63e14c6-9920-58ad-a2a6-b387b9be13c8', '60945554-3420-5dee-bc58-9e959287038d', 'princess', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pɹɪnˈsɛs/', 'audio/princess.mp3', 'A female member of a royal family other than a queen, especially a daughter or granddaughter.', 'Princess Grace was the Princess of Monaco.', 'Society & Culture', 'công chúa', 'Một thành viên nữ của hoàng gia không phải là nữ hoàng, đặc biệt là con gái hoặc cháu gái.', 'Công nương Grace là Công chúa của Monaco.'),
    ('592b0a1e-ba9b-5244-b176-318dd714ca84', '60945554-3420-5dee-bc58-9e959287038d', 'religion', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɹɪˈlɪdʒən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/religion-uk.mp3', 'Belief in a spiritual or metaphysical reality (often including at least one deity), accompanied by practices or rituals pertaining to the belief.', 'My brother tends to value religion, but my sister not as much.', 'Society & Culture', 'tôn giáo', 'Niềm tin vào một thực tại tâm linh hoặc siêu hình (thường bao gồm ít nhất một vị thần), đi kèm với các thực hành hoặc nghi lễ liên quan đến niềm tin đó.', 'Anh trai tôi có xu hướng coi trọng tôn giáo, nhưng chị gái tôi thì không nhiều như vậy.'),
    ('9f0b4561-3519-5749-b5c8-494b8558d074', '60945554-3420-5dee-bc58-9e959287038d', 'religious', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ɹɪ.ˈlɪ.d͡ʒəs/', 'audio/religious.mp3', 'A member of a religious order, i.e. a monk or nun.', 'It is the job of this court to rule on legal matters. We do not consider religious issues.', 'Society & Culture', 'tôn giáo', 'Một thành viên của một dòng tu, tức là một tu sĩ hoặc nữ tu.', 'Nhiệm vụ của tòa án này là phán quyết về các vấn đề pháp lý. Chúng tôi không xem xét các vấn đề tôn giáo.'),
    ('84d6f423-d440-55e4-a715-e6d3b193165f', '60945554-3420-5dee-bc58-9e959287038d', 'respect', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ɹɪˈspɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/respect-uk.mp3', 'An attitude of consideration or high regard', 'He is an intellectual giant, and I have great respect for him.', 'Society & Culture', 'sự tôn trọng', 'Thái độ coi trọng hoặc đánh giá cao.', 'Ông ấy là một trí tuệ khổng lồ, và tôi rất tôn trọng ông ấy.'),
    ('55bc1cab-ef01-5c12-a559-c1b9fc1abc92', '60945554-3420-5dee-bc58-9e959287038d', 'royal', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈɹɔɪəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/royal-us.mp3', 'A royal person; a member of a royal family.', 'royal mast; royal sail', 'Society & Culture', 'hoàng gia', 'Một người thuộc hoàng gia; một thành viên của gia đình hoàng gia.', 'cột buồm chính; cánh buồm chính'),
    ('ce639076-55a3-520b-9d1c-81130ef2529b', '60945554-3420-5dee-bc58-9e959287038d', 'spirit', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈspɪɹɪt/', 'audio/spirit.mp3', 'The soul of a person or other creature. What moves through experience into self-definition as souls purpose.', 'A wandering spirit haunts the island.', 'Society & Culture', 'linh hồn', 'Linh hồn của một người hoặc sinh vật khác. Điều di chuyển qua trải nghiệm để tự định nghĩa như mục đích của linh hồn.', 'Một linh hồn lang thang ám ảnh hòn đảo.'),
    ('feb6f498-e907-5faa-b9f8-637510844d8e', '60945554-3420-5dee-bc58-9e959287038d', 'stranger', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈstɹeɪndʒə/', 'audio/stranger.mp3', 'Not normal; odd, unusual, surprising, out of the ordinary.', 'He thought it strange that his girlfriend wore shorts in the winter.', 'Society & Culture', 'người lạ', 'Không bình thường; kỳ quặc, khác thường, đáng ngạc nhiên, ngoài thông thường.', 'Anh ấy thấy lạ khi bạn gái mình mặc quần đùi vào mùa đông.'),
    ('3f5775b0-4bb8-5b81-b332-152680ab1846', '60945554-3420-5dee-bc58-9e959287038d', 'trend', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/tɹɛnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/trend-uk.mp3', 'An inclination in a particular direction.', 'the trend of a coastline', 'Society & Culture', 'xu hướng', 'Một khuynh hướng theo một hướng cụ thể.', 'xu hướng của đường bờ biển'),
    ('3cb679ed-13b7-5df0-8ad9-9eac95c3a300', '60945554-3420-5dee-bc58-9e959287038d', 'truth', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/tɹuːθ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/truth-us.mp3', 'True facts, genuine depiction or statements of reality.', 'The truth is that our leaders knew a lot more than they were letting on.', 'Society & Culture', 'sự thật, chân lý', 'Sự thật, mô tả hoặc tuyên bố chân thực về thực tế.', 'Sự thật là các nhà lãnh đạo của chúng ta biết nhiều hơn nhiều so với những gì họ tiết lộ.'),
    ('2482ecf0-6ef0-5a19-962f-8f420ae6daaf', '60945554-3420-5dee-bc58-9e959287038d', 'victim', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈvɪktəm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/victim-us.mp3', 'One that is harmed—killed, injured, subjected to oppression, deceived, or otherwise adversely affected—by someone or something, especially another person or event, force, or condition; in particular:', 'the youngest victims of the brutal war', 'Society & Culture', 'nạn nhân', 'Người bị tổn hại—bị giết, bị thương, bị áp bức, bị lừa dối, hoặc bị ảnh hưởng tiêu cực—bởi ai đó hoặc điều gì đó, đặc biệt là một người khác hoặc một sự kiện, lực lượng, hoặc điều kiện; cụ thể là:', 'những nạn nhân trẻ nhất của cuộc chiến tranh tàn bạo'),
    ('64a26682-14f7-5b2e-89c6-377bf56a9f28', '60945554-3420-5dee-bc58-9e959287038d', 'volunteer', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/vɒl.ənˈtɪə/', 'audio/volunteer.mp3', 'One who enters into, or offers for, any service of his/her own free will, especially when done without pay.', 'to volunteer for doing the dishes', 'Society & Culture', 'tình nguyện viên', 'Người tự nguyện tham gia hoặc đề nghị cho bất kỳ dịch vụ nào, đặc biệt khi làm mà không được trả lương.', 'tình nguyện rửa bát'),
    ('25fc4fc9-f6d4-5e6d-8bbe-bbcd9b90e02b', '60945554-3420-5dee-bc58-9e959287038d', 'worldwide', 'B1', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "adv", "level": "B1"}]'::jsonb, '/ˈwɜːldwaɪd/', 'audio/worldwide.mp3', 'Spanning the world; global.', 'A large meteorite impact would cause worldwide extinction of life.', 'Society & Culture', 'toàn cầu', 'Trải rộng khắp thế giới; toàn cầu.', 'Một vụ va chạm thiên thạch lớn sẽ gây ra sự tuyệt chủng trên toàn cầu của sự sống.'),
    ('d6598991-7482-5da2-8e15-2e0297b9944a', '60945554-3420-5dee-bc58-9e959287038d', 'youth', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/juθ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/youth-us.mp3', 'The quality or state of being young.', 'Her youth and beauty attracted him to her.', 'Society & Culture', 'tuổi trẻ, thanh niên', 'Phẩm chất hoặc trạng thái của sự trẻ trung.', 'Tuổi trẻ và vẻ đẹp của cô ấy đã thu hút anh ta đến với cô.'),
    ('41f28862-6f66-5a68-b93e-aeef12f2feab', '60945554-3420-5dee-bc58-9e959287038d', 'celebration', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˌsɛlɪˈbɹeiʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/celebration-uk.mp3', 'The formal performance of a solemn rite, such as Christian sacrament.', NULL, 'Society & Culture', 'lễ kỷ niệm', 'Việc thực hiện chính thức một nghi thức trang trọng, chẳng hạn như bí tích của Cơ đốc giáo.', NULL),
    ('c32884b1-4eb9-53cc-96b9-6b5ac4627d59', '60945554-3420-5dee-bc58-9e959287038d', 'ceremony', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈsɛɹɪməni/', 'audio/ceremony.mp3', 'A ritual, with religious or cultural significance.', NULL, 'Society & Culture', 'nghi lễ', 'Một nghi thức, có ý nghĩa tôn giáo hoặc văn hóa.', NULL),
    ('1a63298c-aeb1-52b5-bf87-dbbe4a078e38', '60945554-3420-5dee-bc58-9e959287038d', 'cultural', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈkʌlt͡ʃəɹəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cultural-us.mp3', 'Pertaining to culture.', NULL, 'Society & Culture', 'thuộc văn hóa', 'Liên quan đến văn hóa.', NULL),
    ('21ee65b3-bd7c-57b9-9dca-5e86ccf346e3', '60945554-3420-5dee-bc58-9e959287038d', 'immigrant', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɪmɪɡɹənt/', 'audio/immigrant.mp3', 'A non-native person who comes to a country from another country in order to permanently settle there.', NULL, 'Society & Culture', 'người nhập cư', 'Một người không phải bản địa đến một quốc gia từ một quốc gia khác để định cư vĩnh viễn ở đó.', NULL),
    ('b731dd96-45be-5e3a-b7af-662bbc69f248', '60945554-3420-5dee-bc58-9e959287038d', 'participate', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/pɑːˈtɪsɪpeɪt/', 'audio/participate.mp3', 'To join in, to take part, to involve oneself (in something).', NULL, 'Society & Culture', 'tham gia', 'Tham gia, dự phần, tự mình tham gia (vào việc gì đó).', NULL),
