    ('d958ab85-3684-5b20-89f1-fa0a0821d0a7', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'effective', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/əˈfɛktɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/effective-us.mp3', 'A soldier fit for duty', 'The pill is an effective method of birth control.', 'Business & Economy', 'hiệu quả', 'Một người lính đủ sức khỏe để làm nhiệm vụ', 'Viên thuốc là một phương pháp kiểm soát sinh đẻ hiệu quả.'),
    ('b26f4f1b-0ca7-539f-9e5d-5a7762ddc7fc', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'exchange', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ɛksˈtʃeɪndʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/exchange-us.mp3', 'An act of exchanging or trading.', 'All in all, it was an even exchange.', 'Business & Economy', 'trao đổi', 'Hành động trao đổi hoặc buôn bán.', 'Nhìn chung, đó là một cuộc trao đổi công bằng.'),
    ('74873c06-394d-54c6-b772-1515f5a06f87', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'expand', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ɛkˈspænd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/expand-uk.mp3', 'To change (something) from a smaller form and/or size to a larger one; to spread out or lay open.', 'You can expand this compact umbrella to cover a large table.', 'Business & Economy', 'mở rộng', 'Thay đổi (thứ gì đó) từ hình thức và/hoặc kích thước nhỏ hơn sang lớn hơn; trải ra hoặc mở ra.', 'Bạn có thể mở rộng chiếc ô gọn nhẹ này để che một cái bàn lớn.'),
    ('0787131f-372b-5e3f-adf2-982ed1678bb0', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'export', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈɛks.pɔːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/export-uk.mp3', 'Something that is exported', 'Oil is the main export of Saudi Arabia.', 'Business & Economy', 'xuất khẩu', 'Thứ gì đó được xuất khẩu', 'Dầu mỏ là mặt hàng xuất khẩu chính của Ả Rập Xê-út.'),
    ('92de710e-5641-529b-ba8f-c66e4233fd63', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'financial', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/faɪˈnænʃəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/financial-us.mp3', 'Related to finances.', 'For financial reasons, we''re not going to be able to continue to fund this program.', 'Business & Economy', 'thuộc tài chính', 'Liên quan đến tài chính.', 'Vì lý do tài chính, chúng tôi sẽ không thể tiếp tục tài trợ cho chương trình này.'),
    ('9b63ac2d-5e4b-51e0-abec-d9a7876fd9e2', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'growth', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɡɹəʊθ/', 'audio/growth.mp3', 'An increase in size, number, value, or strength.', 'Growth was dampened by a softening of the global economy in 2001, but picked up in the subsequent years due to strong growth in China.', 'Business & Economy', 'sự tăng trưởng', 'Sự gia tăng về kích thước, số lượng, giá trị hoặc sức mạnh.', 'Tăng trưởng bị hạn chế bởi sự suy yếu của nền kinh tế toàn cầu vào năm 2001, nhưng đã tăng tốc trong những năm tiếp theo do tăng trưởng mạnh ở Trung Quốc.'),
    ('431c095c-7b93-5066-a91f-04c29fa68877', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'import', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈɪm.pɔːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/import-uk.mp3', 'Something brought in from an exterior source, especially for sale or trade.', 'It was a matter of great import.', 'Business & Economy', 'nhập khẩu', 'Thứ gì đó được đưa vào từ một nguồn bên ngoài, đặc biệt để bán hoặc trao đổi.', 'Đó là một vấn đề rất quan trọng.'),
    ('1558dcf1-3c39-5511-b196-44d9ec1d35d5', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'invest', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ɪnˈvɛst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/invest-uk.mp3', 'To spend money, time, or energy on something, especially for some benefit or purpose; used with in.', 'We''d like to thank all the contributors who have invested countless hours into this event.', 'Business & Economy', 'đầu tư', 'Chi tiêu tiền bạc, thời gian hoặc năng lượng vào thứ gì đó, đặc biệt vì lợi ích hoặc mục đích nào đó; thường dùng với ''in''.', 'Chúng tôi muốn cảm ơn tất cả những người đóng góp đã đầu tư vô số giờ vào sự kiện này.'),
    ('8687954e-09ae-5754-975f-5b69fd143557', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'issue', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈɪsjuː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/issue-uk.mp3', 'The action or an instance of flowing or coming out, an outflow, particularly:', 'The issue of the directive from the treasury prompted the central bank''s most recent issue of currency.', 'Business & Economy', 'vấn đề, phát hành', 'Hành động hoặc một trường hợp chảy ra hoặc đi ra, một dòng chảy ra, cụ thể là:', 'Việc ban hành chỉ thị từ kho bạc đã thúc đẩy đợt phát hành tiền tệ gần đây nhất của ngân hàng trung ương.'),
    ('622bf38d-c668-54ac-a662-b30e30a1e0ec', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'organized', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈɔːɡənaɪzd/', 'audio/organized.mp3', 'To arrange in working order.', 'an organized being', 'Business & Economy', 'được tổ chức', 'Sắp xếp theo trật tự hoạt động.', 'một sinh vật có tổ chức'),
    ('7e27d91c-6e5e-5e63-accc-e898ad6606b5', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'production', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pɹəˈdʌkʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/production-uk.mp3', 'The act of producing, making or creating something.', 'The widget making machine is being used for production now.', 'Business & Economy', 'sản xuất', 'Hành động sản xuất, tạo ra hoặc tạo ra một cái gì đó.', 'Máy làm widget hiện đang được sử dụng cho sản xuất.'),
    ('3ebcd74f-cf03-5c21-a2f1-d02c5a5257bc', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'profit', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɹɒfɪt/', 'audio/profit.mp3', 'Total income or cash flow minus expenditures. The money or other benefit a non-governmental organization or individual receives in exchange for products and services sold at an advertised price.', 'Reading such an enlightening book on the subject was of much profit to his studies.', 'Business & Economy', 'lợi nhuận', 'Tổng thu nhập hoặc dòng tiền trừ đi chi phí. Số tiền hoặc lợi ích khác mà một tổ chức phi chính phủ hoặc cá nhân nhận được để đổi lấy sản phẩm và dịch vụ được bán ở mức giá đã công bố.', 'Việc đọc một cuốn sách mở mang trí tuệ về chủ đề này đã mang lại nhiều lợi ích cho việc học của anh ấy.'),
    ('d3c3143d-31ab-59b2-bb6b-d8d4f5f4fbb0', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'property', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɹɒp.ət.i/', 'audio/property.mp3', 'Something that is owned.', 'Important types of property include real property (land), personal property (other physical possessions), and intellectual property (rights over artistic creations, inventions, etc.).', 'Business & Economy', 'tài sản', 'Thứ gì đó được sở hữu.', 'Các loại tài sản quan trọng bao gồm bất động sản (đất đai), động sản (các tài sản vật chất khác) và tài sản trí tuệ (quyền đối với các sáng tạo nghệ thuật, phát minh, v.v.).'),
    ('d604e52e-2d98-5257-a9fc-7b490bfea7ba', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'range', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ɹeɪndʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/range-us.mp3', 'A line or series of mountains, buildings, etc.', 'We sell a wide range of cars.', 'Business & Economy', 'dải, phạm vi', 'Một dãy hoặc chuỗi núi, tòa nhà, v.v.', 'Chúng tôi bán một loạt ô tô đa dạng.'),
    ('e388fdab-27a5-53dd-8663-a52a780be9ef', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'represent', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ɹɛp.ɹɪ.ˈzɛnt/', 'audio/represent.mp3', 'To present again or anew; to present by means of something standing in the place of; to exhibit the counterpart or image of; to typify.', 'The sculptor represented a horse in bronze.', 'Business & Economy', 'đại diện', 'Trình bày lại hoặc mới; trình bày bằng cách sử dụng thứ gì đó đại diện; thể hiện hình ảnh hoặc bản sao; tượng trưng.', 'Nhà điêu khắc đã thể hiện một con ngựa bằng đồng.'),
    ('5c80f130-b50b-58c1-b7df-bff452c9e70a', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'resource', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɹɪˈsɔɹs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/resource-ca.mp3', 'Something that one uses to achieve an objective, e.g. raw materials or personnel.', 'a man/woman of resource', 'Business & Economy', 'nguồn lực', 'Thứ gì đó người ta sử dụng để đạt được mục tiêu, ví dụ như nguyên liệu thô hoặc nhân sự.', 'một người đàn ông/phụ nữ đầy tài năng'),
    ('1cfcfdc8-2599-59ac-8f84-1fe4d84b357c', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'risk', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ɹɪsk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/risk-us.mp3', 'A possible adverse event or outcome', '2006, Trever Ramsey on BBC News website, Exercise ''cuts skin cancer risk'' read at http//news.bbc.co.uk/1/hi/health/4764535.stm on 14 May 2006', 'Business & Economy', 'rủi ro', 'Một sự kiện hoặc kết quả bất lợi có thể xảy ra', '2006, Trever Ramsey trên trang web BBC News, ''Tập thể dục làm giảm nguy cơ ung thư da'' đọc tại http//news.bbc.co.uk/1/hi/health/4764535.stm vào ngày 14 tháng 5 năm 2006'),
    ('eaacc63e-0515-5e29-b9b6-3173e46bd67e', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'supply', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/səˈplaɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/supply-1-us.mp3', 'The act of supplying.', 'supply and demand', 'Business & Economy', 'cung cấp, nguồn cung', 'Hành động cung cấp.', 'cung và cầu'),
    ('24350f14-ad90-50b6-bd47-e7216e2a2dbf', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'tax', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/tæks/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tax-us.mp3', 'Money paid to the government other than for transaction-specific goods and services.', 'a heavy tax on time or health', 'Business & Economy', 'thuế', 'Tiền nộp cho chính phủ không phải để đổi lấy hàng hóa và dịch vụ cụ thể.', 'một khoản thuế nặng về thời gian hoặc sức khỏe'),
    ('676a2e24-eab7-51e8-8ec7-bff1319d3e60', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'trade', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/tɹeɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/trade-uk.mp3', 'Buying and selling of goods and services on a market.', 'I did no trades with them once the rumors started.', 'Business & Economy', 'thương mại, buôn bán', 'Việc mua bán hàng hóa và dịch vụ trên thị trường.', 'Tôi đã không giao dịch nào với họ một khi những tin đồn bắt đầu.'),
    ('52db729b-9bbd-5094-a9e7-74d8c0e62b4b', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'value', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈvæljuː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/value-us.mp3', 'The quality (positive or negative) that renders something desirable or valuable.', 'The Shakespearean Shylock is of dubious value in the modern world.', 'Business & Economy', 'giá trị', 'Phẩm chất (tích cực hoặc tiêu cực) làm cho một thứ gì đó trở nên mong muốn hoặc có giá trị.', 'Nhân vật Shylock của Shakespeare có giá trị đáng ngờ trong thế giới hiện đại.'),
    ('a5f9a5c2-416c-5427-9aa8-8d1931992a30', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'worth', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/wɜːθ/', 'audio/worth.mp3', 'Value.', 'I’ll have a dollar''s worth of candy, please.', 'Business & Economy', 'giá trị', 'Giá trị.', 'Làm ơn cho tôi kẹo trị giá một đô la.'),
    ('1742d54e-ba63-5cbe-97ad-e9cd73031ece', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'marketing', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, NULL, 'audio/marketing.mp3', 'To make (products or services) available for sale and promote them.', 'We plan to market an ecology model by next quarter.', 'Business & Economy', 'tiếp thị', 'Làm cho (sản phẩm hoặc dịch vụ) có sẵn để bán và quảng bá chúng.', 'Chúng tôi dự định tiếp thị một mô hình sinh thái vào quý tới.'),
    ('b0c0404a-5967-5b26-9128-99febf2bff7e', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'reject', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, NULL, 'audio/reject.mp3', 'Something that is rejected.', 'She even rejected my improved offer.', 'Business & Economy', 'từ chối', 'Một cái gì đó bị từ chối.', 'Cô ấy thậm chí từ chối đề nghị được cải thiện của tôi.'),
    ('043f6e23-58be-526d-b964-c20696e40ee1', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'client', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈklʌɪənt/', 'audio/client.mp3', 'A customer, a buyer or receiver of goods or services.', NULL, 'Business & Economy', 'khách hàng', 'Một khách hàng, một người mua hoặc người nhận hàng hóa hoặc dịch vụ.', NULL),
    ('cc76f213-509d-5b5e-8906-3cd8a7e7c01e', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'commercial', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/kəˈmɜːʃəl/', 'audio/commercial.mp3', 'An advertisement in a common media format, usually radio or television.', NULL, 'Business & Economy', 'quảng cáo', 'Một quảng cáo ở định dạng truyền thông phổ biến, thường là đài phát thanh hoặc truyền hình.', NULL),
    ('f60ca366-66bc-52ae-b277-983d263b94c7', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'economic', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˌiːkəˈnɒmɪk/', 'audio/economic.mp3', 'Pertaining to an economy.', NULL, 'Business & Economy', 'thuộc kinh tế', 'Liên quan đến nền kinh tế.', NULL),
    ('95528cc6-9815-5746-aafd-873d4351b6ef', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'organizer', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɔɹɡənaɪzɚ/', 'audio/organizer.mp3', 'A person who arranges the details of a public event.', NULL, 'Business & Economy', 'người tổ chức', 'Một người sắp xếp các chi tiết của một sự kiện công cộng.', NULL),
    ('c0691fc2-eca7-503d-86ea-49bfa59fd9e5', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'producer', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pɹəˈdjuːsə/', 'audio/producer.mp3', 'An individual or organization that creates goods and services.', NULL, 'Business & Economy', 'nhà sản xuất', 'Một cá nhân hoặc tổ chức tạo ra hàng hóa và dịch vụ.', NULL),
    ('fd32310a-c48f-55f6-88d3-022ca4e8ca33', 'a693b98d-a697-5f73-9806-ecce322b30e0', 'effectively', 'B1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B1"}]'::jsonb, NULL, 'audio/effectively.mp3', 'In an efficient or effective manner; with powerful effect.', NULL, 'Business & Economy', 'một cách hiệu quả', 'Một cách hiệu quả hoặc có tác dụng; với hiệu quả mạnh mẽ.', NULL)
