    ('5e30ac57-2234-52ae-8b1d-e53412ac2dc9', '2e0bd0b4-bd05-505d-a60c-9e3a1bfca253', 'shiny', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈʃaɪni/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shiny-us.mp3', 'Anything shiny; a trinket.', NULL, 'Appearance & Description', 'sáng bóng', 'Bất cứ thứ gì sáng bóng; một món đồ trang sức nhỏ.', NULL),
    ('8528d008-2bbe-5638-a8a0-8f57693c4722', '2e0bd0b4-bd05-505d-a60c-9e3a1bfca253', 'suitable', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈsuːtəbl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/suitable-uk.mp3', 'Having sufficient or the required properties for a certain purpose or task; appropriate to a certain occasion.', NULL, 'Appearance & Description', 'phù hợp, thích hợp', 'Có đủ hoặc các tính chất cần thiết cho một mục đích hoặc nhiệm vụ nhất định; phù hợp với một dịp nhất định.', NULL),
    ('52aaf3d6-2af6-5550-8c8f-0f3b0957c42f', '2e0bd0b4-bd05-505d-a60c-9e3a1bfca253', 'tiny', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈtaɪni/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tiny-us.mp3', 'A small child; an infant.', NULL, 'Appearance & Description', 'nhỏ xíu', 'Một đứa trẻ nhỏ; một trẻ sơ sinh.', NULL),
    ('925a44fe-7be1-5986-9a6a-fd24c7e8c1e9', '2e0bd0b4-bd05-505d-a60c-9e3a1bfca253', 'tight', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, NULL, 'audio/tight.mp3', NULL, NULL, 'Appearance & Description', 'chặt, khít', NULL, NULL)
