INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('8911742b-d425-559e-b012-29f7b2cbb34d', 'a633b468-0af4-511a-a645-eef842cf91f3', 'contrast', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈkɒntɹɑːst/', 'audio/contrast.mp3', 'A difference in lightness, brightness and/or hue between two colours that makes them more or less distinguishable.', 'Israel is a country of many contrasts.', 'Arts & Entertainment', 'tương phản', 'Sự khác biệt về độ sáng, độ tươi sáng và/hoặc sắc thái giữa hai màu khiến chúng dễ hoặc khó phân biệt hơn.', 'Israel là một đất nước của nhiều sự tương phản.'),
    ('d133b6a1-60f5-509c-a6bc-7d3c555841cc', 'a633b468-0af4-511a-a645-eef842cf91f3', 'costume', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkɒs.tjuːm/', 'audio/costume.mp3', 'A style of dress, including garments, accessories and hairstyle, especially as characteristic of a particular country, period or people.', 'The dancer was wearing Highland costume.', 'Arts & Entertainment', 'trang phục', 'Một phong cách ăn mặc, bao gồm quần áo, phụ kiện và kiểu tóc, đặc biệt là đặc trưng của một quốc gia, thời kỳ hoặc dân tộc cụ thể.', 'Vũ công đang mặc trang phục vùng cao nguyên Scotland.'),
    ('809ced62-75e8-5797-ae8e-0b8251bbddce', 'a633b468-0af4-511a-a645-eef842cf91f3', 'drum', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈdɹʌm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/drum-au.mp3', 'A percussive musical instrument spanned with a thin covering on at least one end for striking, forming an acoustic chamber, affecting what materials are used to make it; a membranophone.', 'Replace the drum unit of your printer.', 'Arts & Entertainment', 'trống', 'Một nhạc cụ gõ được căng bằng một lớp màng mỏng ở ít nhất một đầu để gõ, tạo thành một buồng cộng hưởng, ảnh hưởng đến vật liệu dùng để chế tạo nó; một nhạc cụ màng.', 'Thay đơn vị trống của máy in của bạn.'),
    ('275622f6-e618-56c3-b3e4-c27af2924098', 'a633b468-0af4-511a-a645-eef842cf91f3', 'entertain', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ˌɛntəˈteɪn/', 'audio/entertain.mp3', 'Entertainment; pleasure.', 'The motivational speaker not only instructed but also entertained the audience.', 'Arts & Entertainment', 'giải trí', 'Giải trí; niềm vui.', 'Diễn giả truyền động lực không chỉ hướng dẫn mà còn giải trí cho khán giả.'),
    ('6d369ad7-fbe9-5ffa-b1ca-fbb177bb54ca', 'a633b468-0af4-511a-a645-eef842cf91f3', 'episode', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɛpɪsəʊd/', 'audio/episode.mp3', 'An incident, action, or time period standing out by itself, but more or less connected with a complete series of events.', 'It was a most embarrassing episode in my life.', 'Arts & Entertainment', 'tập', 'Một sự việc, hành động, hoặc khoảng thời gian nổi bật, nhưng ít nhiều có liên kết với một chuỗi sự kiện hoàn chỉnh.', 'Đó là một tập phim đáng xấu hổ nhất trong cuộc đời tôi.'),
    ('742c1cdb-3565-5270-b712-a700b4ddfefc', 'a633b468-0af4-511a-a645-eef842cf91f3', 'exhibition', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɛksɪˈbɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/exhibition-us.mp3', 'An instance of exhibiting, or something exhibited.', 'There was an art exhibition on in the town hall.', 'Arts & Entertainment', 'triển lãm', 'Một trường hợp trưng bày, hoặc thứ gì đó được trưng bày.', 'Có một cuộc triển lãm nghệ thuật đang diễn ra tại tòa thị chính.'),
    ('ad4808dd-ff90-5b37-8a23-6b506840c5c9', 'a633b468-0af4-511a-a645-eef842cf91f3', 'highlight', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ˈhaɪ.ˌlaɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/highlight-us.mp3', 'An area or a spot in a drawing, painting, or photograph that is strongly illuminated.', 'Meeting my future wife was the highlight of my trip to Spain.', 'Arts & Entertainment', 'điểm nhấn', 'Một khu vực hoặc một điểm trong bản vẽ, bức tranh hoặc bức ảnh được chiếu sáng mạnh.', 'Gặp vợ tương lai của tôi là điểm nhấn trong chuyến đi Tây Ban Nha của tôi.'),
    ('1c4e5d29-de50-55ff-8c19-954f7c635e2a', 'a633b468-0af4-511a-a645-eef842cf91f3', 'literature', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈlɪ.tə.ɹɪ.tʃə(ɹ)/', 'audio/literature.mp3', 'The body of all written works.', 'However, even “literary” science fiction rarely qualifies as literature, because it treats characters as sets of traits rather than as fully realized human beings with unique life stories. —Adam Cadre, 2008', 'Arts & Entertainment', 'văn học', 'Toàn bộ các tác phẩm viết.', 'Tuy nhiên, ngay cả khoa học viễn tưởng ''văn học'' hiếm khi đủ tiêu chuẩn là văn học, bởi vì nó coi các nhân vật như một tập hợp các đặc điểm hơn là những con người được hiện thực hóa đầy đủ với những câu chuyện đời độc đáo. —Adam Cadre'),
    ('52baad04-6de6-5aba-af58-55818fedb820', 'a633b468-0af4-511a-a645-eef842cf91f3', 'magic', 'B1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "adj", "level": "B1"}]'::jsonb, '/ˈmadʒɪk/', 'audio/magic.mp3', 'The application of rituals or actions, especially those based on occult knowledge, to subdue or manipulate natural or supernatural beings and forces in order to have some benefit from them', 'a magic moment', 'Arts & Entertainment', 'ma thuật', 'Việc áp dụng các nghi lễ hoặc hành động, đặc biệt dựa trên kiến thức huyền bí, để khuất phục hoặc thao túng các sinh vật và lực lượng tự nhiên hoặc siêu nhiên nhằm đạt được lợi ích từ chúng.', 'một khoảnh khắc kỳ diệu'),
    ('babff416-b9c4-504a-b03f-885fc66676d7', 'a633b468-0af4-511a-a645-eef842cf91f3', 'medium', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈmiːdɪəm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/medium-us.mp3', '(plural media or mediums) The chemistry of the surrounding environment, e.g. solid, liquid, gas, vacuum, or a specific substance such as a solvent.', 'Acrylics, oils, charcoal, and gouache are all mediums I used in my painting.', 'Arts & Entertainment', 'phương tiện, chất liệu', '(số nhiều media hoặc mediums) Hóa học của môi trường xung quanh, ví dụ: rắn, lỏng, khí, chân không, hoặc một chất cụ thể như dung môi.', 'Sơn acrylic, dầu, than chì và màu gouache đều là những chất liệu tôi dùng trong bức vẽ của mình.'),
    ('679e9ba4-89ea-54af-9f09-632b1a25b0df', 'a633b468-0af4-511a-a645-eef842cf91f3', 'narrative', 'B1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "adj", "level": "B1"}]'::jsonb, '/ˈnæɹətɪv/', 'audio/narrative.mp3', 'The systematic recitation of an event or series of events.', 'The plot is full of holes, but the narrative is extremely compelling.', 'Arts & Entertainment', 'tường thuật', 'Sự kể lại có hệ thống về một sự kiện hoặc chuỗi sự kiện.', 'Cốt truyện đầy lỗ hổng, nhưng phần tường thuật cực kỳ hấp dẫn.'),
    ('754a8837-5f59-56b0-afc9-d2e63be67eb5', 'a633b468-0af4-511a-a645-eef842cf91f3', 'performance', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '[pə.ˈfɔː.məns]', 'audio/performance.mp3', 'The act of performing; carrying into execution or action; execution; achievement; accomplishment; representation by action.', 'the performance of an undertaking or a duty', 'Arts & Entertainment', 'buổi biểu diễn, hiệu suất', 'Hành động biểu diễn; đưa vào thực hiện hoặc hành động; sự thực thi; thành tựu; thành quả; sự thể hiện bằng hành động.', 'việc thực hiện một cam kết hoặc một nhiệm vụ'),
    ('824a76a7-2689-541d-8a06-60b66520fbac', 'a633b468-0af4-511a-a645-eef842cf91f3', 'plot', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/plɒt/', 'audio/plot.mp3', '(authorship) The course of a story, comprising a series of incidents which are gradually unfolded, sometimes by unexpected means.', 'The assassination of Lincoln was part of a larger plot.', 'Arts & Entertainment', 'cốt truyện', '(tác giả) Diễn biến của một câu chuyện, bao gồm một loạt sự kiện được dần dần hé lộ, đôi khi bằng những phương tiện bất ngờ.', 'Vụ ám sát Lincoln là một phần của một âm mưu lớn hơn.'),
    ('c0cada10-668e-5c92-a3a0-2d0d827a4464', 'a633b468-0af4-511a-a645-eef842cf91f3', 'poetry', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpəʊɪtɹi/', 'audio/poetry.mp3', 'Literature composed in verse or language exhibiting conscious attention to patterns and rhythm.', 'That ''Swan Lake'' choreography is poetry in motion, fitting the musical poetry of Tchaikovski''s divine score well beyond the literary inspiration.', 'Arts & Entertainment', 'thơ ca', 'Văn học được sáng tác bằng thơ hoặc ngôn ngữ thể hiện sự chú ý có ý thức đến hình mẫu và nhịp điệu.', 'Biên đạo múa ''Hồ Thiên Nga'' đó là thơ ca trong chuyển động, phù hợp với thơ ca âm nhạc của bản nhạc thiêng liêng của Tchaikovsky vượt xa cảm hứng văn học.'),
    ('95f1ff02-c031-5491-93d8-9dae04ea8b15', 'a633b468-0af4-511a-a645-eef842cf91f3', 'portrait', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɔːtɹeɪt/', 'audio/portrait.mp3', 'A painting or other picture of a person, especially the head and shoulders.', 'The author painted a good portrait of urban life in New York in his latest book.', 'Arts & Entertainment', 'chân dung', 'Một bức tranh hoặc hình ảnh khác về một người, đặc biệt là phần đầu và vai.', 'Tác giả đã vẽ nên một bức chân dung tốt về cuộc sống đô thị ở New York trong cuốn sách mới nhất của ông.'),
    ('9c267e2b-17f5-5df8-9ef5-8991f5cf9242', 'a633b468-0af4-511a-a645-eef842cf91f3', 'quotation', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/kwoʊˈteɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/quotation-us.mp3', 'A fragment of a human expression that is repeated by somebody else. Most often a quotation is taken from literature or speech, but also scenes from a movie, elements of a painting, a passage of music, etc., may be quoted.', '"Where they burn books, they will also burn people" is a famous quotation from Heinrich Heine.', 'Arts & Entertainment', 'trích dẫn', 'Một đoạn trích từ lời nói của con người được ai đó khác lặp lại. Thông thường, một trích dẫn được lấy từ văn học hoặc lời nói, nhưng cũng có thể là cảnh trong phim, yếu tố của bức tranh, đoạn nhạc,', '"Nơi nào họ đốt sách, họ cũng sẽ đốt người" là một câu trích dẫn nổi tiếng của Heinrich Heine.'),
    ('d3e8e611-9d70-5fa8-84e2-180b06344a3f', 'a633b468-0af4-511a-a645-eef842cf91f3', 'quote', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/kwəʊt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/quote-us.mp3', 'A quotation; a statement attributed to a person.', 'After going over the hefty quotes, the board decided it was cheaper to have the project executed by its own staff.', 'Arts & Entertainment', 'trích dẫn', 'Một lời trích dẫn; một tuyên bố được cho là của một người.', 'Sau khi xem xét các báo giá cao ngất ngưởng, hội đồng quyết định sẽ rẻ hơn nếu để nhân viên của chính mình thực hiện dự án.'),
    ('fa967ab7-e923-5d94-a27a-465107a1bb7f', 'a633b468-0af4-511a-a645-eef842cf91f3', 'romantic', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ɹə-/', 'audio/romantic.mp3', 'Of or dealing with languages or cultures derived from Roman influence and Latin: Italian, French, Portuguese, Spanish, Romanian, Catalan, Occitan, Corsican, etc.', 'Oh, flowers! You''re such a romantic.', 'Arts & Entertainment', 'lãng mạn', 'Thuộc về hoặc liên quan đến các ngôn ngữ hoặc nền văn hóa bắt nguồn từ ảnh hưởng của La Mã và Latinh: Ý, Pháp, Bồ Đào Nha, Tây Ban Nha, Romania, Catalan, Occitan, Corsica, v.v.', 'Ôi, hoa! Anh thật lãng mạn.'),
    ('e035bca6-0bef-57b2-896d-5c16ccf3a75c', 'a633b468-0af4-511a-a645-eef842cf91f3', 'sharp', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ʃɑːp/', 'audio/sharp.mp3', 'The symbol ♯, placed after the name of a note in the key signature or before a note on the staff to indicate that the note is to be played a semitone higher.', 'The pitch pipe sounded out a perfect F♯ (F sharp).', 'Arts & Entertainment', 'sắc', 'Ký hiệu ♯, được đặt sau tên của một nốt nhạc trong khóa nhạc hoặc trước một nốt trên khuông nhạc để chỉ ra rằng nốt đó phải được chơi cao hơn nửa cung.', 'Ống thổi âm thanh phát ra một nốt F♯ (F thăng) hoàn hảo.'),
    ('9d7f2a84-95d6-5de8-a541-bbccad49caa2', 'a633b468-0af4-511a-a645-eef842cf91f3', 'studio', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈstjuːdiəʊ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/studio-uk.mp3', 'An artist’s or photographer’s workshop or the room in which an artist works.', 'His studio was cramped when he began as an artist.', 'Arts & Entertainment', 'xưởng phim, phòng thu', 'Xưởng làm việc của một nghệ sĩ hoặc nhiếp ảnh gia hoặc căn phòng mà một nghệ sĩ làm việc.', 'Xưởng vẽ của anh ấy rất chật chội khi anh mới bắt đầu sự nghiệp nghệ thuật.'),
    ('4828ded1-a9b4-5656-ae2f-081cb98008ff', 'a633b468-0af4-511a-a645-eef842cf91f3', 'theme', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/θiːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/theme-us.mp3', 'A subject of a talk or an artistic piece; a topic.', 'We themed the birthday party around superheroes.', 'Arts & Entertainment', 'chủ đề', 'Chủ đề của một bài nói hoặc một tác phẩm nghệ thuật; một đề tài.', 'Chúng tôi chọn chủ đề cho bữa tiệc sinh nhật xoay quanh các siêu anh hùng.'),
    ('f1a34d41-bbb8-5dc0-abbc-0b3badd7e720', 'a633b468-0af4-511a-a645-eef842cf91f3', 'trick', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/tɹɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/trick-us.mp3', 'Something designed to fool or swindle.', 'It was just a trick to say that the house was underpriced.', 'Arts & Entertainment', 'trò lừa, mẹo', 'Thứ gì đó được thiết kế để lừa dối hoặc lừa đảo.', 'Đó chỉ là một mánh khóe khi nói rằng ngôi nhà được định giá thấp hơn giá trị.'),
    ('ca902750-ad67-5b1f-a28f-b4ac18c41b69', 'a633b468-0af4-511a-a645-eef842cf91f3', 'version', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈvɜːʃən/', 'audio/version.mp3', 'A specific form or variation of something.', 'It''s only in the King James Version of the Bible.', 'Arts & Entertainment', 'phiên bản', 'Một dạng hoặc biến thể cụ thể của một cái gì đó.', 'Nó chỉ có trong Bản dịch King James của Kinh Thánh.'),
    ('cbb493a8-8308-5e37-9fe9-bf3813de0b45', 'a633b468-0af4-511a-a645-eef842cf91f3', 'western', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈwɛstən/', 'audio/western.mp3', 'A film, or some other dramatic work, set in, the historic (c. 1850-1910) American West (west of the Mississippi river) focusing on conflict between whites and Indians, lawmen and outlaws, ranchers and farmers, or industry (railroads, mining) and agriculture.', 'the western approaches', 'Arts & Entertainment', 'phương Tây, phim cao bồi', 'Một bộ phim, hoặc một số tác phẩm kịch khác, lấy bối cảnh ở miền Tây nước Mỹ lịch sử (khoảng 1850-1910) (phía tây sông Mississippi) tập trung vào xung đột giữa người da trắng và người da đỏ, cảnh sát và ngoài vòng pháp luật, chủ trang trại và', 'các lối tiếp cận phía tây'),
    ('5e98a6e0-d222-54ba-9203-66f440d0981a', 'a633b468-0af4-511a-a645-eef842cf91f3', 'album', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈælbəm/', 'audio/album.mp3', 'A book specially designed to keep photographs, stamps, or autographs.', NULL, 'Arts & Entertainment', 'album', 'Một cuốn sách được thiết kế đặc biệt để lưu giữ ảnh, tem hoặc chữ ký.', NULL),
    ('4e457d4a-50b7-5578-9999-be3f21e5cc3e', 'a633b468-0af4-511a-a645-eef842cf91f3', 'documentary', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˌdɒk.jəˈmɛn.tɹi/', 'audio/documentary.mp3', 'A film, TV program, publication etc. which presents a social, political, scientific or historical subject in a factual or informative manner.', NULL, 'Arts & Entertainment', 'phim tài liệu', 'Một bộ phim, chương trình TV, ấn phẩm, v.v. trình bày một chủ đề xã hội, chính trị, khoa học hoặc lịch sử một cách thực tế hoặc cung cấp thông tin.', NULL),
    ('bb0983ea-af6c-5407-8acb-8ead83d64942', 'a633b468-0af4-511a-a645-eef842cf91f3', 'entertainment', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɛn.tɚˈteɪn.mənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/entertainment-us.mp3', 'An activity designed to give pleasure, enjoyment, diversion, amusement, or relaxation to an audience, no matter whether the audience participates passively as in watching opera or a movie, or actively as in games.', NULL, 'Arts & Entertainment', 'sự giải trí', 'Một hoạt động được thiết kế để mang lại niềm vui, sự thích thú, tiêu khiển, giải trí hoặc thư giãn cho khán giả, bất kể khán giả tham gia thụ động như khi xem opera hay phim, hay chủ động', NULL),
    ('f2cdc284-e073-5b48-b998-2b55a917c7ea', 'a633b468-0af4-511a-a645-eef842cf91f3', 'photographer', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/fəˈtɒɡɹəfə/', 'audio/photographer.mp3', 'One who takes photographs, typically as an occupation.', NULL, 'Arts & Entertainment', 'nhiếp ảnh gia', 'Người chụp ảnh, thường như một nghề nghiệp.', NULL),
    ('da3844a2-afb7-56f1-a99c-98f6f58b76c2', 'a633b468-0af4-511a-a645-eef842cf91f3', 'photography', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/fəˈtɒɡɹəfi/', 'audio/photography.mp3', 'The art and technology of producing images on photosensitive surfaces, and its digital counterpart.', NULL, 'Arts & Entertainment', 'nhiếp ảnh', 'Nghệ thuật và công nghệ tạo ra hình ảnh trên các bề mặt nhạy sáng, và phiên bản kỹ thuật số của nó.', NULL),
    ('e518ff63-a85a-56d5-a4e1-95b7f3281d07', 'a633b468-0af4-511a-a645-eef842cf91f3', 'poem', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpoʊ̯ɪm/', 'audio/poem.mp3', 'A literary piece written in verse.', NULL, 'Arts & Entertainment', 'bài thơ', 'Một tác phẩm văn học được viết bằng thơ.', NULL),
    ('4c0985ad-8b65-5c74-bd28-edebacd3507c', 'a633b468-0af4-511a-a645-eef842cf91f3', 'poet', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpəʊɪt/', 'audio/poet.mp3', 'A person who writes poems.', NULL, 'Arts & Entertainment', 'nhà thơ', 'Một người viết thơ.', NULL),
    ('56449473-63b3-5315-9dea-775202727506', 'a633b468-0af4-511a-a645-eef842cf91f3', 'script', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/skɹɪpt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/script-us.mp3', 'A writing; a written document.', NULL, 'Arts & Entertainment', 'kịch bản', 'Một văn bản; một tài liệu viết.', NULL),
    ('848d09a0-282f-5461-81b2-750fea16571f', 'a633b468-0af4-511a-a645-eef842cf91f3', 'sculpture', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈskʌlptj(ʊ)ə/', 'audio/sculpture.mp3', 'A three dimensional work of art created by shaping malleable objects and letting them harden or by chipping away pieces from a rock (sculpting).', NULL, 'Arts & Entertainment', 'tác phẩm điêu khắc', 'Một tác phẩm nghệ thuật ba chiều được tạo ra bằng cách định hình các vật thể dễ uốn và để chúng cứng lại hoặc bằng cách đục đẽo từ một tảng đá (điêu khắc).', NULL),
    ('594fa0b4-e776-5953-a85f-d4ddfa44d10d', 'a633b468-0af4-511a-a645-eef842cf91f3', 'statue', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈstæt.juː/', 'audio/statue.mp3', 'A three-dimensional work of art, usually representing a person or animal, usually created by sculpting, carving, molding, or casting.', NULL, 'Arts & Entertainment', 'bức tượng', 'Một tác phẩm nghệ thuật ba chiều, thường đại diện cho một người hoặc động vật, thường được tạo ra bằng cách điêu khắc, chạm khắc, đúc khuôn hoặc đúc.', NULL),
    ('b468b7ca-81b8-56b2-b208-9805e046fcf6', 'a633b468-0af4-511a-a645-eef842cf91f3', 'viewer', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, NULL, 'audio/viewer.mp3', 'Someone who views a spectacle; an onlooker or spectator.', NULL, 'Arts & Entertainment', 'người xem', 'Người xem một cảnh tượng; một người xem hoặc khán giả.', NULL),
    ('2b85cbce-8349-5c4c-bd60-c8f035587909', 'a633b468-0af4-511a-a645-eef842cf91f3', 'live2', 'B1', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "adv", "level": "B1"}]'::jsonb, NULL, 'audio/live2.mp3', NULL, NULL, 'Arts & Entertainment', 'trực tiếp', NULL, NULL)
