    ('3bcc10ca-685c-51b6-91a8-452f24a311f0', '0bdad76d-ae13-5615-b665-3129abec221d', 'attract', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/əˈtɹækt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/attract-uk.mp3', 'To pull toward without touching.', 'A magnet attracts iron filings.', 'Science & Research', 'thu hút', 'Kéo về phía mà không chạm vào.', 'Nam châm hút các mạt sắt.'),
    ('46b6d171-aa83-59a9-8663-3712ed6e1598', '0bdad76d-ae13-5615-b665-3129abec221d', 'attraction', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/əˈtɹækʃən/', 'audio/attraction.mp3', 'The tendency to attract.', 'The Moon is held in its orbit by the attraction of the Earth''s gravity.', 'Science & Research', 'sự thu hút', 'Xu hướng thu hút.', 'Mặt Trăng được giữ trong quỹ đạo của nó bởi lực hấp dẫn của Trái Đất.'),
    ('f08b2482-d460-5e34-9879-a276173b82d0', '0bdad76d-ae13-5615-b665-3129abec221d', 'base', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/beɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/base-us.mp3', 'Something from which other things extend; a foundation.', 'The logarithm to base 2 of 8 is 3.', 'Science & Research', 'cơ sở, nền tảng', 'Thứ mà từ đó các thứ khác mở rộng; một nền tảng.', 'Lôgarit cơ số 2 của 8 là 3.'),
    ('73a89bbe-4114-585d-85f2-c661a41c9471', '0bdad76d-ae13-5615-b665-3129abec221d', 'bubble', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈbʌb.əl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bubble-us.mp3', 'A spherically contained volume of air or other gas, especially one made from soapy liquid.', 'bubbles in window glass, or in a lens', 'Science & Research', 'bong bóng', 'Một thể tích không khí hoặc khí khác được chứa trong hình cầu, đặc biệt là một bong bóng được tạo ra từ chất lỏng có xà phòng.', 'bong bóng trong kính cửa sổ, hoặc trong một thấu kính'),
    ('fd997e62-1e88-57bc-9ea8-fdddd846bb83', '0bdad76d-ae13-5615-b665-3129abec221d', 'combine', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/kəmˈbaɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/combine-uk.mp3', 'A combine harvester', 'We can''t finish harvesting because our combine is stuck in the mud.', 'Science & Research', 'kết hợp', 'Một máy gặt đập liên hợp', 'Chúng tôi không thể hoàn thành thu hoạch vì máy gặt đập liên hợp của chúng tôi bị mắc kẹt trong bùn.'),
    ('94353760-cee9-5db0-a10d-b01d2347ad75', '0bdad76d-ae13-5615-b665-3129abec221d', 'current', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈkʌɹənt/', 'audio/current.mp3', 'The generally unidirectional movement of a gas or fluid.', 'current events; current leaders; current negotiations', 'Science & Research', 'dòng chảy/hiện tại', 'Chuyển động chủ yếu một chiều của khí hoặc chất lỏng.', 'sự kiện hiện tại; lãnh đạo hiện tại; đàm phán hiện tại'),
    ('24b583a5-1069-54c1-96d0-93fd7fd3739b', '0bdad76d-ae13-5615-b665-3129abec221d', 'element', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɛlɪmənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/element-us.mp3', 'One of the simplest or essential parts or principles of which anything consists, or upon which the constitution or fundamental powers of anything are based.', 'Letters are the elements of written language.', 'Science & Research', 'nguyên tố, yếu tố', 'Một trong những phần hoặc nguyên lý đơn giản hoặc cần thiết nhất cấu thành nên bất cứ thứ gì, hoặc là nền tảng cho hiến pháp hoặc quyền lực cơ bản của bất cứ thứ gì.', 'Chữ cái là những yếu tố cơ bản của ngôn ngữ viết.'),
    ('5945cfc4-9611-547b-9dc1-fd04fa6a31cf', '0bdad76d-ae13-5615-b665-3129abec221d', 'explode', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ɪkˈspləʊd/', 'audio/explode.mp3', 'To destroy with an explosion.', 'The assassin exploded the car by means of a car bomb.', 'Science & Research', 'nổ tung', 'Phá hủy bằng một vụ nổ.', 'Kẻ ám sát đã cho nổ tung chiếc xe bằng bom xe.'),
    ('d2d302a7-3314-5db9-a747-5334fe1a2477', '0bdad76d-ae13-5615-b665-3129abec221d', 'explore', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ɪkˈsplɔː/', 'audio/explore.mp3', 'An exploration; a tour of a place to see what it is like.', 'The committee has been exploring alternative solutions to the problem at hand.', 'Science & Research', 'khám phá', 'Một cuộc thám hiểm; một chuyến tham quan một nơi để xem nó như thế nào.', 'Ủy ban đã khám phá các giải pháp thay thế cho vấn đề hiện tại.'),
    ('62a3fa59-489a-50c5-84ee-1f9a6023d206', '0bdad76d-ae13-5615-b665-3129abec221d', 'flow', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/fləʊ/', 'audio/flow.mp3', 'A movement in people or things with a particular way in large numbers or amounts', 'The notion of flow is basic to the study of ordinary differential equations.', 'Science & Research', 'dòng chảy', 'Một chuyển động trong con người hoặc sự vật với một cách cụ thể với số lượng lớn.', 'Khái niệm dòng chảy là cơ bản cho việc nghiên cứu phương trình vi phân thông thường.'),
    ('db2d7d22-dc83-5d08-a62a-bcce827684f2', '0bdad76d-ae13-5615-b665-3129abec221d', 'force', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/fɔːs/', 'audio/force.mp3', 'Strength or energy of body or mind; active power; vigour; might; capacity of exercising an influence or producing an effect.', 'the force of an appeal, an argument, or a contract', 'Science & Research', 'lực', 'Sức mạnh hoặc năng lượng của cơ thể hoặc tâm trí; sức mạnh tích cực; sức mạnh; khả năng thực hiện ảnh hưởng hoặc tạo ra hiệu ứng.', 'sức mạnh của một lời kêu gọi, một lập luận, hoặc một hợp đồng'),
    ('ffbac736-4d2f-5170-83da-718f2927bc42', '0bdad76d-ae13-5615-b665-3129abec221d', 'investigate', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '[ɪn.ˈves.tɪ.ɡeɪ̯t]', 'https://api.dictionaryapi.dev/media/pronunciations/en/investigate-us.mp3', 'To inquire into or study in order to ascertain facts or information.', 'to investigate the causes of natural phenomena', 'Science & Research', 'điều tra', 'Tìm hiểu hoặc nghiên cứu để xác định sự thật hoặc thông tin.', 'điều tra nguyên nhân của các hiện tượng tự nhiên'),
    ('a81e54a0-a14a-571c-8ccf-79c2f54de650', '0bdad76d-ae13-5615-b665-3129abec221d', 'layer', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/leɪə/', 'audio/layer.mp3', 'A single thickness of some material covering a surface.', 'After the first coat of paint dried, he applied another layer.', 'Science & Research', 'lớp', 'Một độ dày đơn lẻ của một số vật liệu phủ lên bề mặt.', 'Sau khi lớp sơn đầu tiên khô, anh ấy phủ thêm một lớp nữa.'),
    ('d9fb76e5-6ee8-59c4-bf43-9e3938d65dc2', '0bdad76d-ae13-5615-b665-3129abec221d', 'liquid', 'B1', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "adj", "level": "B1"}]'::jsonb, '/ˈlɪkwɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/liquid-us.mp3', 'A substance that is flowing, and keeping no shape, such as water; a substance of which the molecules, while not tending to separate from one another like those of a gas, readily change their relative position, and which therefore retains no definite shape, except that determined by the containing receptacle; an inelastic fluid.', 'A liquid can freeze to become a solid or evaporate into a gas.', 'Science & Research', 'chất lỏng', 'Một chất chảy và không giữ hình dạng, chẳng hạn như nước; một chất mà các phân tử của nó, mặc dù không có xu hướng tách rời nhau như các phân tử của chất khí, dễ dàng thay đổi vị trí tương đối của chúng.', 'Một chất lỏng có thể đông đặc để trở thành chất rắn hoặc bay hơi thành chất khí.'),
    ('c5ad0c50-26ee-562e-8a27-8b3c6b59bd0e', '0bdad76d-ae13-5615-b665-3129abec221d', 'mixture', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈmɪkstʃə/', 'audio/mixture.mp3', 'The act of mixing.', 'A teaspoonful of the mixture to be taken three times daily after meals', 'Science & Research', 'hỗn hợp', 'Hành động trộn lẫn.', 'Một thìa cà phê hỗn hợp uống ba lần mỗi ngày sau bữa ăn'),
    ('48d3a2e5-579d-52b8-8fa5-a4c940d761da', '0bdad76d-ae13-5615-b665-3129abec221d', 'nuclear', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈn(j)ukliɚ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/nuclear-ca.mp3', 'Nuclear power', 'a nuclear reactor', 'Science & Research', 'hạt nhân', 'Năng lượng hạt nhân.', 'một lò phản ứng hạt nhân'),
    ('8c72b0c5-9b61-5a29-96d3-5d14fcce6ea1', '0bdad76d-ae13-5615-b665-3129abec221d', 'prove', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/pɹuːv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/prove-1-us.mp3', 'To proofread.', 'I will prove that my method is more effective than yours.', 'Science & Research', 'chứng minh', 'Để đọc bản in thử.', 'Tôi sẽ chứng minh rằng phương pháp của tôi hiệu quả hơn của bạn.'),
    ('2fdb80f9-9e28-5956-a5cd-2acf28eb65f3', '0bdad76d-ae13-5615-b665-3129abec221d', 'reflect', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ɹɪˈflɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/reflect-us.mp3', 'To bend back (light, etc.) from a surface.', 'A mirror reflects the light that shines on it.', 'Science & Research', 'phản chiếu', 'Để uốn cong lại (ánh sáng, v.v.) từ một bề mặt.', 'Một tấm gương phản chiếu ánh sáng chiếu vào nó.'),
    ('de500e55-5e86-5d41-8001-ff8580b27b1e', '0bdad76d-ae13-5615-b665-3129abec221d', 'sample', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/sæːm.pəl/', 'audio/sample.mp3', 'A part or snippet of something taken or presented for inspection, or shown as evidence of the quality of the whole; a specimen.', 'a blood sample', 'Science & Research', 'mẫu', 'Một phần hoặc đoạn trích của thứ gì đó được lấy hoặc trình bày để kiểm tra, hoặc được hiển thị làm bằng chứng về chất lượng của toàn bộ; một mẫu vật.', 'một mẫu máu'),
    ('288b41e7-1498-5fd8-a9db-fccc355f7f2c', '0bdad76d-ae13-5615-b665-3129abec221d', 'solid', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ˈsɒlɪd/', 'audio/solid.mp3', 'A substance in the fundamental state of matter that retains its size and shape without need of a container (as opposed to a liquid or gas).', 'I owe him; he did me a solid last year.', 'Science & Research', 'chất rắn', 'Một chất ở trạng thái cơ bản của vật chất giữ nguyên kích thước và hình dạng mà không cần vật chứa (trái ngược với chất lỏng hoặc khí).', 'Tôi nợ anh ấy; năm ngoái anh ấy đã giúp tôi một việc lớn.'),
    ('054317ac-e8e3-51c9-a0e3-bae62d915300', '0bdad76d-ae13-5615-b665-3129abec221d', 'substance', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈsʌbstəns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/substance-us.mp3', 'Physical matter; material.', 'Some textile fabrics have little substance.', 'Science & Research', 'chất, vật chất', 'Vật chất; vật liệu.', 'Một số loại vải dệt có rất ít chất liệu.'),
    ('c05163a7-da8a-5790-b104-668354fb978a', '0bdad76d-ae13-5615-b665-3129abec221d', 'surface', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈsɜːfɪs/', 'audio/surface.mp3', 'The overside or up-side of a flat object such as a table, or of a liquid.', 'On the surface, the spy looked like a typical businessman.', 'Science & Research', 'bề mặt', 'Mặt trên hoặc mặt phía trên của một vật phẳng như cái bàn, hoặc của chất lỏng.', 'Trên bề mặt, điệp viên trông giống một doanh nhân điển hình.'),
    ('fbe5612d-ec94-5ae4-80be-0542a199274a', '0bdad76d-ae13-5615-b665-3129abec221d', 'theory', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈθiːəɹi/', 'audio/theory.mp3', 'A description of an event or system that is considered to be accurate.', 'Knot theory classifies the mappings of a circle into 3-space.', 'Science & Research', 'lý thuyết', 'Một mô tả về một sự kiện hoặc hệ thống được coi là chính xác.', 'Lý thuyết nút thắt phân loại các ánh xạ của một vòng tròn vào không gian 3 chiều.'),
    ('c908886c-fb46-5909-a979-5f66800b4477', '0bdad76d-ae13-5615-b665-3129abec221d', 'complex', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, NULL, 'audio/complex.mp3', 'A network of interconnected systems.', 'Jim has a real complex about working for a woman boss.', 'Science & Research', 'phức tạp', 'Một mạng lưới các hệ thống liên kết với nhau.', 'Jim thực sự có mặc cảm về việc làm việc cho một bà sếp.'),
    ('fb401930-6764-5eab-a077-5bc7dd1c07b8', '0bdad76d-ae13-5615-b665-3129abec221d', 'impact', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, NULL, 'audio/impact.mp3', 'The striking of one body against another; collision.', 'The hatchet cut the wood on impact.', 'Science & Research', 'tác động', 'Sự va chạm của một vật thể vào vật thể khác; sự va chạm.', 'Lưỡi rìu cắt vào gỗ ngay khi va chạm.'),
    ('f664ad6e-fcb9-5c87-87b9-0c24fef3133e', '0bdad76d-ae13-5615-b665-3129abec221d', 'statistic', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, NULL, 'audio/statistic.mp3', 'A single item in a statistical study.', 'By dying from an overdose, he became just another statistic.', 'Science & Research', 'thống kê', 'Một mục đơn lẻ trong một nghiên cứu thống kê.', 'Bằng cách chết vì quá liều, anh ta trở thành chỉ một con số thống kê khác.'),
    ('7368f651-b2f8-5b48-ad77-95d327619291', '0bdad76d-ae13-5615-b665-3129abec221d', 'analysis', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/əˈnælɪsɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/analysis-us.mp3', 'Decomposition into components in order to study (a complex thing, concept, theory etc.).', NULL, 'Science & Research', 'sự phân tích', 'Phân tách thành các thành phần để nghiên cứu (một thứ phức tạp, khái niệm, lý thuyết, v.v.).', NULL),
    ('b14fda72-0e3b-5505-9165-abf23bc0d142', '0bdad76d-ae13-5615-b665-3129abec221d', 'chemical', 'B1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ˈkɛmɪkəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chemical-uk.mp3', 'Any specific chemical element or chemical compound or alloy.', NULL, 'Science & Research', 'hóa chất', 'Bất kỳ nguyên tố hóa học cụ thể hoặc hợp chất hóa học hoặc hợp kim nào.', NULL),
    ('aa44f937-4f4a-5286-920b-e8fc2f9c4a28', '0bdad76d-ae13-5615-b665-3129abec221d', 'explosion', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɪkˈspləʊ.ʒən/', 'audio/explosion.mp3', 'A violent release of energy (sometimes mechanical, nuclear, or chemical.)', NULL, 'Science & Research', 'vụ nổ', 'Sự giải phóng năng lượng dữ dội (đôi khi là cơ học, hạt nhân hoặc hóa học).', NULL),
    ('fdd367ba-362c-5d52-a7eb-51b54721acc1', '0bdad76d-ae13-5615-b665-3129abec221d', 'function', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈfʌŋ(k)ʃən/', 'audio/function.mp3', 'What something does or is used for.', NULL, 'Science & Research', 'chức năng', 'Điều gì đó làm hoặc được sử dụng để làm gì.', NULL),
    ('b34503d2-dd0f-5da6-89b3-46a8fd9e0e28', '0bdad76d-ae13-5615-b665-3129abec221d', 'laboratory', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ləˈbɔɹətɹi/', 'audio/laboratory.mp3', 'A room, building or institution equipped for scientific research, experimentation or analysis.', NULL, 'Science & Research', 'phòng thí nghiệm', 'Một căn phòng, tòa nhà hoặc cơ sở được trang bị cho nghiên cứu khoa học, thử nghiệm hoặc phân tích.', NULL),
    ('ca63455d-283d-5d55-90cf-1cc7a522f3f8', '0bdad76d-ae13-5615-b665-3129abec221d', 'prediction', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pɹɪˈdɪkʃn/', 'audio/prediction.mp3', 'A statement of what will happen in the future.', NULL, 'Science & Research', 'dự báo', 'Một tuyên bố về điều sẽ xảy ra trong tương lai.', NULL),
    ('4faf61d9-8730-57f4-b19c-a30fc4181204', '0bdad76d-ae13-5615-b665-3129abec221d', 'scientific', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˌsaɪənˈtɪfɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/scientific-ca.mp3', 'Of, or having to do with science.', NULL, 'Science & Research', 'thuộc khoa học', 'Thuộc về, hoặc có liên quan đến khoa học.', NULL),
    ('0943e111-a20a-5fc6-b489-9092cfdf05d4', '0bdad76d-ae13-5615-b665-3129abec221d', 'analyse', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, NULL, 'audio/analyse.mp3', 'To subject to analysis.', NULL, 'Science & Research', 'phân tích', 'Để đưa ra phân tích.', NULL),
    ('79f66427-82f8-5d65-9254-1e460b4c1ab4', '0bdad76d-ae13-5615-b665-3129abec221d', 'mine (hole in the ground)', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, NULL, 'audio/mine_(hole_in_the_ground).mp3', NULL, NULL, 'Science & Research', 'mỏ', NULL, NULL)
