    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('0fcdc652-7cd4-5fea-b221-742b55c06d51', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'agreement', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/əˈɡɹiːmənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/agreement-us.mp3', 'An understanding between entities to follow a specific course of conduct.', 'to enter an agreement; the UK and US negotiators nearing agreement; he nodded his agreement.', 'Law & Politics', 'thỏa thuận', 'Một sự hiểu biết giữa các thực thể để tuân theo một quá trình hành động cụ thể.', 'đi đến một thỏa thuận; các nhà đàm phán Anh và Mỹ sắp đạt được thỏa thuận; anh ấy gật đầu đồng ý.'),
    ('4c6f5a2f-a326-5495-a93c-4935fbc2331e', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'arrest', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/əˈɹɛst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/arrest-us.mp3', 'A check, stop, an act or instance of arresting something.', 'The police have arrested a suspect in the murder inquiry.', 'Law & Politics', 'bắt giữ', 'Một sự kiểm soát, dừng lại, một hành động hoặc trường hợp ngăn chặn điều gì đó.', 'Cảnh sát đã bắt giữ một nghi phạm trong cuộc điều tra vụ án mạng.'),
    ('7251ac86-c36d-55d7-a114-3b176ed1340f', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'authority', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɔːˈθɒɹəti/', 'audio/authority.mp3', 'The power to enforce rules or give orders.', 'I have the authority to penalise the staff in my department, but not the authority to sack them.', 'Law & Politics', 'thẩm quyền', 'Quyền lực để thực thi các quy tắc hoặc ra lệnh.', 'Tôi có thẩm quyền phạt nhân viên trong phòng của mình, nhưng không có thẩm quyền sa thải họ.'),
    ('81bf2fb1-ce02-543c-9c91-2b7d0edfd664', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'ban', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/bæn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ban-uk.mp3', 'Prohibition.', 'Bans is common and ordinary amongst the Feudists, and signifies a proclamation, or any public notice.', 'Law & Politics', 'cấm, lệnh cấm', 'Sự cấm đoán.', 'Lệnh cấm là phổ biến và thông thường trong giới phong kiến, và có nghĩa là một tuyên bố, hoặc bất kỳ thông báo công khai nào.'),
    ('08187d32-f1d3-5004-9ce7-17fd1d320965', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'bomb', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/bɒm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bomb-au.mp3', 'An explosive device used or intended as a weapon.', 'box office bomb', 'Law & Politics', 'bom', 'Một thiết bị nổ được sử dụng hoặc dự định làm vũ khí.', 'thất bại phòng vé'),
    ('f14a943e-ac3a-5a0e-8882-8c3d8ac6de82', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'claim', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/kleɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/claim-us.mp3', 'A demand of ownership made for something.', 'a claim of ownership', 'Law & Politics', 'yêu sách, đòi hỏi', 'Một yêu cầu về quyền sở hữu đối với một thứ gì đó.', 'một yêu sách về quyền sở hữu'),
    ('e704124f-30cf-51f6-a187-3ff747cb206c', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'commit', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/kəˈmɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/commit-uk.mp3', 'The act of committing (e.g. a database transaction or source code into a source control repository), making it a permanent change.', 'Tony should be committed to a nuthouse!', 'Law & Politics', 'cam kết', 'Hành động cam kết (ví dụ: một giao dịch cơ sở dữ liệu hoặc mã nguồn vào kho lưu trữ mã nguồn), biến nó thành một thay đổi vĩnh viễn.', 'Tony nên bị đưa vào viện tâm thần!'),
    ('69c14df4-6db7-51ac-99ad-a96a0bbfae33', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'court', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/kɔːt/', 'audio/court.mp3', 'An enclosed space; a courtyard; an uncovered area shut in by the walls of a building, or by different buildings; also, a space opening from a street and nearly surrounded by houses; a blind alley.', 'The girls were playing in the court.', 'Law & Politics', 'tòa án', 'Một không gian có tường bao quanh; một sân trong; một khu vực không có mái che được vây kín bởi các bức tường của một tòa nhà, hoặc bởi các tòa nhà khác nhau; cũng là một không gian mở ra từ đường phố và gần như bị bao quanh bởi các ngôi nhà; một ngõ cụt.', 'Các cô gái đang chơi trong sân.'),
    ('ff8bf9d2-5be0-51e2-83f0-c50e56b5e3af', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'duty', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈdjuːti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/duty-uk.mp3', 'That which one is morally or legally obligated to do.', 'We don''t have a duty to keep you here.', 'Law & Politics', 'nghĩa vụ, nhiệm vụ', 'Điều mà một người có nghĩa vụ đạo đức hoặc pháp lý phải làm.', 'Chúng tôi không có nghĩa vụ phải giữ bạn ở đây.'),
    ('1ee6f047-3a81-50d5-9818-54549ce956a9', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'election', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɪˈlɛkʃ(ə)n/', 'audio/election.mp3', 'A process of choosing a leader, members of parliament, councillors or other representatives by popular vote.', 'How did you vote in (UK also: at) the last election?', 'Law & Politics', 'cuộc bầu cử', 'Một quá trình chọn lãnh đạo, thành viên quốc hội, ủy viên hội đồng hoặc các đại diện khác bằng bỏ phiếu phổ thông.', 'Bạn đã bỏ phiếu như thế nào trong cuộc bầu cử vừa rồi?'),
    ('93bfa73b-c11b-5003-a839-084744bcf8ca', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'escape', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/əˈskeɪp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/escape-us.mp3', 'The act of leaving a dangerous or unpleasant situation.', 'The prisoners made their escape by digging a tunnel.', 'Law & Politics', 'trốn thoát', 'Hành động rời khỏi một tình huống nguy hiểm hoặc khó chịu.', 'Các tù nhân đã trốn thoát bằng cách đào một đường hầm.'),
    ('2e309859-bb76-5656-9671-f33bcf825e16', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'guard', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ɡɑːd/', 'audio/guard.mp3', 'A person who, or thing that, protects or watches over something.', 'The prison guard unlocked the door of the cell. After completing the repairs, he replaced the sump guard.', 'Law & Politics', 'vệ sĩ / bảo vệ', 'Một người, hoặc vật, bảo vệ hoặc canh gác thứ gì đó.', 'Cai ngục mở khóa cửa phòng giam. Sau khi hoàn thành việc sửa chữa, anh ấy đã thay thế tấm chắn cacte.'),
    ('b43240ef-8a80-5067-ac02-df5f868bc252', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'guilty', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈɡɪl.ti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/guilty-us.mp3', 'A plea by a defendant who does not contest a charge.', 'He was guilty of cheating at cards.', 'Law & Politics', 'có tội', 'Lời biện hộ của bị cáo không tranh chấp cáo buộc.', 'Anh ta có tội gian lận khi chơi bài.'),
    ('86b2a575-3460-52fa-b9bf-eca55c1a401f', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'illegal', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ɪˈliːɡəl/', 'audio/illegal.mp3', 'An illegal act or technique.', 'Nearly 40 million people live in UK areas with illegal air pollution', 'Law & Politics', 'bất hợp pháp', 'Một hành động hoặc kỹ thuật bất hợp pháp.', 'Gần 40 triệu người sống ở các khu vực của Vương quốc Anh có tình trạng ô nhiễm không khí bất hợp pháp'),
    ('868d34a1-24d1-5b9e-a6de-61a27a258336', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'innocent', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈɪnəsn̩t/', 'https://api.dictionaryapi.dev/media/pronunciations/en/innocent-us.mp3', 'One who is innocent, especially a young child.', 'The slaughter of the innocents was a significant event in the New Testament.', 'Law & Politics', 'vô tội', 'Một người vô tội, đặc biệt là một đứa trẻ nhỏ.', 'Cuộc tàn sát những người vô tội là một sự kiện quan trọng trong Tân Ước.'),
    ('79acde55-c13a-5b04-bdcb-46563bf6c826', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'judge', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/d͡ʒʌd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/judge-us.mp3', 'A public official whose duty it is to administer the law, especially by presiding over trials and rendering judgments; a justice.', 'At a boxing match, the decision of the judges is final.', 'Law & Politics', 'thẩm phán, đánh giá', 'Một công chức có nhiệm vụ thực thi pháp luật, đặc biệt bằng cách chủ trì các phiên tòa và đưa ra phán quyết; một thẩm phán.', 'Tại một trận đấu quyền Anh, quyết định của ban giám khảo là cuối cùng.'),
    ('2f137476-5ff9-5270-a374-0fff23d03f1d', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'legal', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈliː.ɡəl/', 'audio/legal.mp3', 'The legal department of a company.', 'Legal wants this in writing.', 'Law & Politics', 'hợp pháp, pháp lý', 'Bộ phận pháp lý của một công ty.', 'Phòng pháp lý muốn điều này bằng văn bản.'),
    ('881c01fb-2576-5b3f-8fe2-48e3351e7015', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'murder', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈmɜːdə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/murder-uk.mp3', 'The crime of deliberately killing another person without justification.', 'The defendant was charged with murder.', 'Law & Politics', 'giết người', 'Tội ác cố ý giết người khác mà không có lý do chính đáng.', 'Bị cáo bị buộc tội giết người.'),
    ('675a50a5-b4de-5f04-9e0e-4040cbeb93d8', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'policy', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɒləsi/', 'audio/policy.mp3', 'A principle of behaviour, conduct etc. thought to be desirable or necessary, especially as formally expressed by a government or other authoritative body.', 'The Communist Party has a policy of returning power to the workers.', 'Law & Politics', 'chính sách', 'Một nguyên tắc ứng xử, hành vi, v.v. được coi là mong muốn hoặc cần thiết, đặc biệt khi được thể hiện chính thức bởi chính phủ hoặc cơ quan có thẩm quyền khác.', 'Đảng Cộng sản có chính sách trả lại quyền lực cho công nhân.'),
    ('f7e116e5-3494-5f92-9b6f-1f1c7463682d', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'political', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/pəˈlɪtɪkəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/political-us.mp3', 'A political agent or officer.', 'Political principles are rarely absolute, as political logic holds an imperfect result by compromise is better than a theoretically perfect abstention from the political process in the opposition.', 'Law & Politics', 'chính trị', 'Một đại lý hoặc viên chức chính trị.', 'Nguyên tắc chính trị hiếm khi tuyệt đối, vì logic chính trị cho rằng một kết quả không hoàn hảo thông qua thỏa hiệp tốt hơn là một sự kiêng khem về mặt lý thuyết hoàn hảo khỏi quá trình chính trị trong phe đối lập.'),
    ('6e8036d2-98b4-5b9a-865a-4a7a8730b02b', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'politician', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɒl.ɪ.tɪʃ.ən/', 'audio/politician.mp3', 'One engaged in politics, especially an elected or appointed government official.', 'Politicians should serve the country''s interest.', 'Law & Politics', 'chính trị gia', 'Người tham gia vào chính trị, đặc biệt là quan chức chính phủ được bầu hoặc bổ nhiệm.', 'Các chính trị gia nên phục vụ lợi ích quốc gia.'),
    ('1820fd81-b066-575a-9ac5-01f227d0a8f3', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'politics', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɒl.ɪ.tɪks/', 'https://api.dictionaryapi.dev/media/pronunciations/en/politics-uk.mp3', 'To engage in political activity; politick.', 'He made a career out of politics.', 'Law & Politics', 'chính trị', 'Tham gia vào hoạt động chính trị; làm chính trị.', 'Ông ấy đã xây dựng sự nghiệp từ chính trị.'),
    ('08a90013-b38e-5261-bf6d-2b17249dcbd8', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'private', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈpɹaɪvət/', 'https://api.dictionaryapi.dev/media/pronunciations/en/private-us.mp3', 'A soldier of the lowest rank in the army.', 'If you want to learn ballet, consider taking privates.', 'Law & Politics', 'riêng tư', 'Một người lính có cấp bậc thấp nhất trong quân đội.', 'Nếu bạn muốn học ba lê, hãy cân nhắc việc học riêng.'),
    ('5b9bd38a-444a-5ed0-b67f-a5ebd6c00e5d', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'protest', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈpɹəʊ.tɛst/', 'audio/protest.mp3', 'A formal objection, especially one by a group.', 'They lodged a protest with the authorities.', 'Law & Politics', 'phản đối', 'Một sự phản đối chính thức, đặc biệt là của một nhóm.', 'Họ đã đệ trình một bản phản đối lên chính quyền.'),
    ('fc8011ba-adcb-5698-837e-6146f34a1247', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'punish', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ˈpʌnɪʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/punish-us.mp3', 'To cause to suffer for crime or misconduct, to administer disciplinary action.', 'If a prince violates the law, then he must be punished like an ordinary person.', 'Law & Politics', 'trừng phạt', 'Khiến phải chịu đựng vì tội phạm hoặc hành vi sai trái, để thực hiện hành động kỷ luật.', 'Nếu một hoàng tử vi phạm pháp luật, thì anh ta phải bị trừng phạt như một người bình thường.'),
    ('38684308-a008-53b2-a271-e7c3d084a091', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'punishment', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpʌnɪʃmənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/punishment-us.mp3', 'The act or process of punishing, imposing and/or applying a sanction.', 'a vehicle that can take a lot of punishment', 'Law & Politics', 'hình phạt', 'Hành động hoặc quá trình trừng phạt, áp đặt và/hoặc áp dụng một biện pháp trừng phạt.', 'một phương tiện có thể chịu đựng nhiều sự trừng phạt'),
    ('b99f0dfe-6bcb-5f89-af52-3ca0d4962c5a', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'release', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ɹɪˈliːs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/release-1-us.mp3', 'The event of setting (someone or something) free (e.g. hostages, slaves, prisoners, caged animals, hooked or stuck mechanisms).', 'The video store advertised that it had all the latest releases.', 'Law & Politics', 'phóng thích', 'Sự kiện thả tự do (ai đó hoặc cái gì đó) (ví dụ: con tin, nô lệ, tù nhân, động vật bị nhốt, cơ chế bị mắc kẹt).', 'Cửa hàng video quảng cáo rằng họ có tất cả các bản phát hành mới nhất.'),
    ('d62eb6c5-f7c9-5504-85d5-5f5a72e4ab66', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'vote', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/vəʊt/', 'audio/vote.mp3', 'A formalized choice on matters of administration or other democratic activities', 'One occasion indicative votes were used was in 2003 when MPs were presented with seven different options on how to reform the House of Lords.', 'Law & Politics', 'bỏ phiếu', 'Sự lựa chọn được chính thức hóa về các vấn đề hành chính hoặc các hoạt động dân chủ khác.', 'Một dịp mà các cuộc bỏ phiếu thăm dò được sử dụng là vào năm 2003 khi các nghị sĩ được trình bày bảy lựa chọn khác nhau về cách cải cách Thượng viện.'),
    ('745f2498-20c1-530b-bbe3-be7804758e55', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'weapon', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈwɛ.pən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/weapon-us.mp3', 'An instrument of attack or defense in combat or hunting, e.g. most guns, missiles, or swords.', 'The club that is now mostly used for golf was once a common weapon.', 'Law & Politics', 'vũ khí', 'Công cụ tấn công hoặc phòng thủ trong chiến đấu hoặc săn bắn, ví dụ hầu hết súng, tên lửa hoặc kiếm.', 'Cây gậy mà ngày nay chủ yếu được dùng cho golf từng là một vũ khí phổ biến.'),
    ('2db39db5-a279-58f5-8a74-8f9edeba483f', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'candidate', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkæn.dɪdət/', 'audio/candidate.mp3', 'A person who is running in an election.', NULL, 'Law & Politics', 'ứng cử viên', 'Một người đang tranh cử trong một cuộc bầu cử.', NULL),
    ('ab8e103c-8af9-5707-9206-15ae7baba3f7', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'prisoner', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɹɪzənəɹ/', 'audio/prisoner.mp3', 'A person incarcerated in a prison, while on trial or serving a sentence.', NULL, 'Law & Politics', 'tù nhân', 'Một người bị giam giữ trong nhà tù, trong khi chờ xét xử hoặc đang thụ án.', NULL),
    ('75a33f4a-8fbb-5a34-b1ae-e5092307cd9e', 'a1f23b34-797f-52a4-bd55-56a42cf134b0', 'security', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/sɪˈkjɔːɹəti/', 'audio/security.mp3', 'The condition of not being threatened, especially physically, psychologically, emotionally, or financially.', NULL, 'Law & Politics', 'an ninh', 'Tình trạng không bị đe dọa, đặc biệt là về thể chất, tâm lý, cảm xúc, hoặc tài chính.', NULL)
