    ('c780f813-af98-5483-bab9-724b4398fd59', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'bite', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/bʌɪt/', 'audio/bite.mp3', 'The act of biting.', 'That snake bite really hurts!', 'Health & Body', 'cắn', 'Hành động cắn.', 'Vết rắn cắn đó thực sự đau!'),
    ('2645d625-2e97-5f84-9408-4cab49ee637f', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'breath', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/bɹɛθ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/breath-us.mp3', 'The act or process of breathing.', 'I could hear the breath of the runner behind me.', 'Health & Body', 'hơi thở', 'Hành động hoặc quá trình thở.', 'Tôi có thể nghe thấy hơi thở của người chạy phía sau.'),
    ('5d9786fa-e5b4-52d5-a153-5034850889b4', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'breathe', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/bɹiːð/', 'audio/breathe.mp3', 'To draw air into (inhale), and expel air from (exhale), the lungs in order to extract oxygen and excrete waste gases.', 'Fish have gills so they can breathe underwater.', 'Health & Body', 'thở', 'Hít không khí vào (hít vào), và thở không khí ra (thở ra) từ phổi để lấy oxy và thải khí thải.', 'Cá có mang để chúng có thể thở dưới nước.'),
    ('4ab9c2b7-b5f7-59fc-a6ab-b354dd5fed45', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'breathing', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈbɹiːðɪŋ/', 'audio/breathing.mp3', 'To draw air into (inhale), and expel air from (exhale), the lungs in order to extract oxygen and excrete waste gases.', 'Fish have gills so they can breathe underwater.', 'Health & Body', 'hô hấp', 'Hít không khí vào (hít vào), và thở không khí ra (thở ra) từ phổi để lấy oxy và thải khí thải.', 'Cá có mang để chúng có thể thở dưới nước.'),
    ('1ddf65f3-9d8b-5405-986d-425adccfd2f4', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'damage', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈdæmɪdʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/damage-us.mp3', 'Injury or harm; the condition or measure of something not being intact.', 'The storm did a lot of damage to the area.', 'Health & Body', 'thiệt hại', 'Tổn thương hoặc hại; tình trạng hoặc mức độ của một thứ gì đó không còn nguyên vẹn.', 'Cơn bão đã gây ra nhiều thiệt hại cho khu vực.'),
    ('15386c8f-7080-53b9-8dfc-9080a80946b8', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'emergency', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɪˈmɝ.dʒən.si/', 'https://api.dictionaryapi.dev/media/pronunciations/en/emergency-us.mp3', 'A situation which poses an immediate risk and which requires urgent attention.', 'Cardiac arrest is an emergency and if you find someone in cardiac arrest you should call 999 immediately.', 'Health & Body', 'tình trạng khẩn cấp', 'Một tình huống gây ra rủi ro ngay lập tức và đòi hỏi sự chú ý khẩn cấp.', 'Ngừng tim là một tình trạng khẩn cấp và nếu bạn thấy ai đó bị ngừng tim, bạn nên gọi 999 ngay lập tức.'),
    ('4ed15363-e289-5674-bbaf-f20c45b33691', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'killing', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkɪl.ɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/killing-us.mp3', 'To put to death; to extinguish the life of.', 'Smoking kills more people each year than alcohol and drugs combined.', 'Health & Body', 'sự giết chóc', 'Làm cho chết; tước đoạt sự sống.', 'Hút thuốc giết nhiều người mỗi năm hơn rượu và ma túy cộng lại.'),
    ('a53b734c-a2da-5667-bc35-8a232874ce41', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'lip', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/lɪp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lip-us.mp3', 'Either of the two fleshy protrusions around the opening of the mouth.', 'Don’t give me any lip!', 'Health & Body', 'môi', 'Một trong hai phần thịt nhô ra xung quanh lỗ mở của miệng.', 'Đừng có cãi lại tôi!'),
    ('c78309ff-618c-52c1-80b9-dce75b38314b', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'mental', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈmɛntəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mental-us.mp3', 'Of or relating to the mind or an intellectual process.', 'He is the most mental freshman I''ve seen yet.', 'Health & Body', 'thuộc tinh thần, trí óc', 'Thuộc về hoặc liên quan đến tâm trí hoặc quá trình trí tuệ.', 'Anh ấy là sinh viên năm nhất có đầu óc nhất mà tôi từng thấy.'),
    ('8b762eb0-506d-597c-827b-41d5f800c572', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'muscle', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈmʌs.əl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/muscle-us.mp3', 'A contractile form of tissue which animals use to effect movement.', 'Muscle consists largely of actin and myosin filaments.', 'Health & Body', 'cơ bắp', 'Một dạng mô co lại mà động vật dùng để tạo ra chuyển động.', 'Cơ bắp phần lớn gồm các sợi actin và myosin.'),
    ('87ad59bf-41ed-5f9c-9cd9-c8de9fc319a2', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'nail', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/neɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/nail-us.mp3', 'The thin, horny plate at the ends of fingers and toes on humans and some other animals.', 'When I''m nervous I bite my nails.', 'Health & Body', 'móng tay', 'Mảnh sừng mỏng ở đầu ngón tay và ngón chân của con người và một số động vật khác.', 'Khi tôi lo lắng, tôi cắn móng tay.'),
    ('22dec7cd-40bd-53d5-8ca8-9a9f082e8ba0', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'operation', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˌɒpəˈɹeɪʃən/', 'audio/operation.mp3', 'The method by which a device performs its function.', 'The Katrina relief operation was considered botched.', 'Health & Body', 'cuộc phẫu thuật', 'Phương pháp mà một thiết bị thực hiện chức năng của nó.', 'Chiến dịch cứu trợ Katrina được coi là thất bại.'),
    ('5f831700-4ca4-5eed-804d-11b5c5dffea2', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'painful', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈpeɪn.fəl/', 'audio/painful.mp3', 'Causing pain or distress, either physical or mental.', 'His violin playing is painful.', 'Health & Body', 'đau đớn', 'Gây ra đau đớn hoặc khó chịu, về thể chất hoặc tinh thần.', 'Tiếng chơi violin của anh ấy thật đau tai.'),
    ('22d7e2eb-1086-55d5-8044-b4a0269f427a', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'poison', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈpɔɪz(ə)n/', 'https://api.dictionaryapi.dev/media/pronunciations/en/poison-us.mp3', 'A substance that is harmful or lethal to a living organism.', 'We used a poison to kill the weeds.', 'Health & Body', 'chất độc', 'Một chất có hại hoặc gây chết người cho sinh vật sống.', 'Chúng tôi đã dùng chất độc để diệt cỏ dại.'),
    ('9df2b068-ae96-58c5-b60b-cef316f0c869', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'pressure', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '[ˈpɹɛʃ.ə(ɹ)]', 'audio/pressure.mp3', 'A pressing; a force applied to a surface.', 'Apply pressure to the wound to stop the bleeding.', 'Health & Body', 'áp lực', 'Sự ép; một lực tác dụng lên một bề mặt.', 'Ấn mạnh vào vết thương để cầm máu.'),
    ('585a53e7-c3ad-517b-91c8-737f2ae4d37c', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'safety', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈseɪfti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/safety-us.mp3', 'The condition or feeling of being safe; security; certainty.', 'If you push it to the limit, safety is not guaranteed.', 'Health & Body', 'sự an toàn', 'Tình trạng hoặc cảm giác được an toàn; sự bảo đảm; sự chắc chắn.', 'Nếu bạn đẩy nó đến giới hạn, sự an toàn không được đảm bảo.'),
    ('141aae89-38a9-56ef-990a-eee3adc74403', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'sex', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/sɛks/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sex-us.mp3', 'A category into which sexually-reproducing organisms are divided on the basis of their reproductive roles in their species.', 'The effect of the medication is dependent upon age, sex, and other factors.', 'Health & Body', 'giới tính', 'Một danh mục mà các sinh vật sinh sản hữu tính được chia dựa trên vai trò sinh sản của chúng trong loài.', 'Tác dụng của thuốc phụ thuộc vào tuổi, giới tính và các yếu tố khác.'),
    ('fb02c3ed-e382-5d71-807a-196be7756395', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'sexual', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈsɛksjuəl/', 'audio/sexual.mp3', 'A species which reproduces by sexual rather than asexual reproduction, or a member of such a species.', 'Women face sexual discrimination in the workplace.', 'Health & Body', 'tình dục', 'Một loài sinh sản bằng cách sinh sản hữu tính hơn là vô tính, hoặc một thành viên của loài đó.', 'Phụ nữ phải đối mặt với sự phân biệt giới tính tại nơi làm việc.'),
    ('8f71e1ed-2be4-5499-8042-df1e9d5f26f0', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'sight', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/saɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sight-us.mp3', '(in the singular) The ability to see.', 'He is losing his sight and now can barely read.', 'Health & Body', 'thị lực', '(số ít) Khả năng nhìn thấy.', 'Ông ấy đang mất thị lực và giờ hầu như không thể đọc được.'),
    ('cc1fc20b-6497-58e0-9ef9-9e39aadabd1e', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'strength', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/stɹɛŋkθ/', 'audio/strength.mp3', 'The quality or degree of being strong.', 'It requires great strength to lift heavy objects.', 'Health & Body', 'sức mạnh', 'Chất lượng hoặc mức độ mạnh mẽ.', 'Cần có sức mạnh lớn để nâng các vật nặng.'),
    ('fb314b7b-2064-5190-8f74-d6af9de6983b', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'suffer', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ˈsʌfə/', 'audio/suffer.mp3', 'To undergo hardship.', 'Is anyone here afraid of suffering hardship?', 'Health & Body', 'chịu đựng, trải qua', 'Trải qua sự khó khăn, gian khổ.', 'Có ai ở đây sợ phải chịu đựng gian khổ không?'),
    ('f9cfcc99-39ec-51a0-ba92-083da3471b05', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'survive', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/səˈvʌɪv/', 'audio/survive.mp3', 'Of a person, to continue to live; to remain alive.', 'His children survived him; he was survived by his children.', 'Health & Body', 'sống sót', 'Về một người, tiếp tục sống; duy trì sự sống.', 'Những đứa con của ông sống sót sau ông; ông được những đứa con sống sót sau mình.'),
    ('025f18c1-399e-5063-b0bd-4aa1df3daac8', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'throat', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈθɹəʊt/', 'audio/throat.mp3', 'The front part of the neck.', 'The wild pitch bounced and hit the catcher in the throat.', 'Health & Body', 'cổ họng', 'Phần trước của cổ.', 'Quả ném bóng hoang dã nảy lên và đập vào cổ họng của người bắt bóng.'),
    ('fab81f94-8bc6-563d-9fd7-ba7f792c3f68', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'toe', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/təʊ/', 'audio/toe.mp3', 'Each of the five digits on the end of the foot.', 'to toe the mark', 'Health & Body', 'ngón chân', 'Mỗi ngón trong năm ngón ở cuối bàn chân.', 'đứng sát vạch xuất phát'),
    ('d0838fe2-ffba-52f2-99cb-26c71179c662', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'tongue', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/tʌŋ/', 'audio/tongue.mp3', 'The flexible muscular organ in the mouth that is used to move food around, for tasting and that is moved into various positions to modify the flow of air from the lungs in order to produce different sounds in speech.', 'cold tongue with mustard', 'Health & Body', 'lưỡi', 'Cơ quan cơ bắp linh hoạt trong miệng được dùng để di chuyển thức ăn xung quanh, để nếm và được di chuyển vào các vị trí khác nhau để điều chỉnh luồng không khí từ phổi nhằm tạo ra các âm thanh khác nhau.', 'thịt lưỡi lạnh với mù tạt'),
    ('e8f54963-4d4b-5bde-bb53-3c636286879e', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'treatment', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈtɹiːtmənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/treatment-us.mp3', 'The process or manner of treating someone or something.', 'He still has nightmares resulting from the treatment he received from his captors.', 'Health & Body', 'điều trị, cách đối xử', 'Quá trình hoặc cách thức đối xử với ai đó hoặc thứ gì đó.', 'Anh ấy vẫn còn những cơn ác mộng do cách đối xử anh nhận được từ những kẻ bắt giữ mình.'),
    ('8c0ba84e-4edb-5629-b3db-e50e68f790df', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'fitness', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈfɪtnəs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fitness-us.mp3', 'The condition of being fit, suitable or appropriate.', NULL, 'Health & Body', 'thể lực', 'Tình trạng khỏe mạnh, phù hợp hoặc thích hợp.', NULL),
    ('85d9f86f-535d-543f-ab9e-c476d7ad950f', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'injure', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ˈɪndʒə/', 'audio/injure.mp3', 'To wound or cause physical harm to a living creature.', NULL, 'Health & Body', 'làm bị thương', 'Gây thương tích hoặc tổn hại thể chất cho một sinh vật sống.', NULL),
    ('820767d3-1a2d-5dd1-b269-b10963cd308b', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'injured', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈɪndʒəd/', 'audio/injured.mp3', 'To wound or cause physical harm to a living creature.', NULL, 'Health & Body', 'bị thương', 'Gây thương tích hoặc tổn hại thể chất cho một sinh vật sống.', NULL),
    ('a41b2b60-bd35-59f9-91fa-52be06917297', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'poisonous', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈpɔɪznəs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/poisonous.mp3', 'Containing sufficient poison to be dangerous to touch or ingest.', NULL, 'Health & Body', 'có độc', 'Chứa đủ chất độc để nguy hiểm khi chạm vào hoặc ăn phải.', NULL),
    ('7979be72-e198-5099-a312-308e6a2e1ab5', 'ed7d0f49-5715-5039-a54b-e79d048a030f', 'symptom', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈsɪm(p)təm/', 'audio/symptom.mp3', 'A perceived change in some function, sensation or appearance of a person that indicates a disease or disorder, such as fever, headache or rash.', NULL, 'Health & Body', 'triệu chứng', 'Một sự thay đổi có thể nhận thấy trong một số chức năng, cảm giác hoặc biểu hiện bên ngoài của một người cho thấy bệnh tật hoặc rối loạn, chẳng hạn như sốt, đau đầu hoặc phát ban.', NULL)
