INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('401574c4-649c-5f89-a447-770b215ff462', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'branch', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/bɹæntʃ/', 'audio/branch.mp3', 'The woody part of a tree arising from the trunk and usually dividing.', 'the branch of an antler, a chandelier, or a railway', 'Nature & Environment', 'cành cây', 'Phần gỗ của cây mọc ra từ thân và thường phân nhánh.', 'cành của gạc hươu, đèn chùm hoặc đường sắt'),
    ('c0281f51-ce02-5eef-bca2-4ea94c170c0a', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'coal', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/kɔʊl/', 'audio/coal.mp3', 'A black rock formed from prehistoric plant remains, composed largely of carbon and burned as a fuel.', 'Put some coal on the fire.', 'Nature & Environment', 'than đá', 'Một loại đá màu đen hình thành từ tàn tích thực vật thời tiền sử, chủ yếu cấu tạo từ carbon và được đốt làm nhiên liệu.', 'Cho thêm than vào lửa.'),
    ('868856b2-911a-58ba-8797-a9a039cb088a', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'countryside', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkʌn.tɹiˌsaɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/countryside-uk.mp3', 'A rural area, or the rural part of a larger area.', 'We live in the Swedish countryside.', 'Nature & Environment', 'vùng quê', 'Một khu vực nông thôn, hoặc phần nông thôn của một khu vực lớn hơn.', 'Chúng tôi sống ở vùng quê Thụy Điển.'),
    ('de4bc812-9279-50f2-8cfb-dbfdcc704cb8', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'diamond', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈdaɪ(ə)mənd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/diamond-us.mp3', 'A glimmering glass-like mineral that is an allotrope of carbon in which each atom is surrounded by four others in the form of a tetrahedron.', 'The saw is coated with diamond.', 'Nature & Environment', 'kim cương', 'Một khoáng chất giống như thủy tinh lấp lánh, là một dạng thù hình của carbon trong đó mỗi nguyên tử được bao quanh bởi bốn nguyên tử khác dưới dạng một tứ diện.', 'Lưỡi cưa được phủ kim cương.'),
    ('32a6d5a7-758e-5399-af9a-b7f73a55462e', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'dirt', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/dɜːt/', 'audio/dirt.mp3', 'Soil or earth.', 'The reporter uncovered the dirt on the businessman by going undercover.', 'Nature & Environment', 'đất, bụi bẩn', 'Đất hoặc đất cát.', 'Phóng viên đã khám phá ra tin xấu về doanh nhân bằng cách hoạt động ngầm.'),
    ('21a2e81f-52df-5d66-99d9-a62faa082193', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'dust', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/dʌst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dust-us.mp3', 'Fine particles', 'to raise, or kick up, a dust', 'Nature & Environment', 'bụi', 'Những hạt nhỏ li ti', 'làm bụi bay lên, hoặc đá bụi lên'),
    ('4c4e134e-cc66-5108-8108-66db29185b2d', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'flood', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/flʌd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/flood-us.mp3', 'A (usually disastrous) overflow of water from a lake or other body of water due to excessive rainfall or other input of water.', 'a flood of complaints', 'Nature & Environment', 'lũ lụt', 'Một sự tràn nước (thường thảm khốc) từ hồ hoặc vùng nước khác do lượng mưa quá mức hoặc lượng nước đầu vào khác.', 'một loạt các khiếu nại'),
    ('6eb47c98-ccd5-5f9d-9821-51b265e3a503', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'global', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈɡləʊbəl/', 'audio/global.mp3', 'A globally scoped identifier.', 'Pollution is a global problem.', 'Nature & Environment', 'toàn cầu', 'Một định danh có phạm vi toàn cầu.', 'Ô nhiễm là một vấn đề toàn cầu.'),
    ('6cf3a5c5-73da-57c4-b4ee-0be82b9cefc1', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'leaf', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/liːf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/leaf-us.mp3', 'The usually green and flat organ that represents the most prominent feature of most vegetative plants.', 'gold leaf', 'Nature & Environment', 'lá cây', 'Cơ quan thường có màu xanh và dẹt, đại diện cho đặc điểm nổi bật nhất của hầu hết các loài thực vật.', 'lá vàng'),
    ('99dbb079-7384-5f0f-87c2-a6f14be8dfd0', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'mud', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/mʌd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mud-us.mp3', 'A mixture of water and soil or fine grained sediment.', 'The campaign issues got lost in all the mud from both parties.', 'Nature & Environment', 'bùn', 'Một hỗn hợp của nước và đất hoặc trầm tích hạt mịn.', 'Các vấn đề vận động tranh cử đã bị lạc mất trong tất cả bùn đất từ cả hai đảng.'),
    ('6eac23ea-7b61-590f-84d8-8db67e1d0902', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'naturally', 'B1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B1"}]'::jsonb, '/ˈnætʃ(ə)ɹəli/', 'https://api.dictionaryapi.dev/media/pronunciations/en/naturally-us.mp3', 'In a natural manner.', 'Although he was unused to the situation, he tried to act naturally.', 'Nature & Environment', 'một cách tự nhiên', 'Một cách tự nhiên.', 'Mặc dù anh ấy không quen với tình huống, anh ấy cố gắng hành xử một cách tự nhiên.'),
    ('0313d0f9-546a-5cdf-9495-86b13315b7c3', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'northern', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈnɔːðn̩/', 'audio/northern.mp3', 'An inhabitant of the northern regions.', 'Les Dawson was a famous northern comedian.', 'Nature & Environment', 'thuộc miền bắc', 'Một cư dân của vùng phía bắc.', 'Les Dawson là một diễn viên hài miền bắc nổi tiếng.'),
    ('8acad24b-ba85-5a53-894d-5e76adaa69b5', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'path', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '[pʰäːθ]', 'audio/path.mp3', 'A trail for the use of, or worn by, pedestrians.', 'the path of a meteor, of a caravan, or of a storm', 'Nature & Environment', 'con đường, lối đi', 'Một lối mòn dành cho người đi bộ sử dụng, hoặc bị mòn do người đi bộ.', 'quỹ đạo của một thiên thạch, của một đoàn lữ hành, hoặc của một cơn bão'),
    ('51fd77d8-cc90-5f2e-a67a-6d6cd9e0c345', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'sand', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/sænd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sand-us.mp3', 'Rock that is ground more finely than gravel, but is not as fine as silt (more formally, see grain sizes chart), forming beaches and deserts and also used in construction.', 'The Canadian tar sands are a promising source of oil.', 'Nature & Environment', 'cát', 'Đá được nghiền mịn hơn sỏi, nhưng không mịn bằng bùn (theo cách chính thức hơn, xem biểu đồ kích thước hạt), tạo thành bãi biển và sa mạc và cũng được sử dụng trong xây dựng.', 'Cát dầu Canada là một nguồn dầu triển vọng.'),
    ('d4e69c9f-ba5f-5e04-a388-5a2d99c3073b', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'seed', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/siːd/', 'audio/seed.mp3', 'A fertilized and ripened ovule, containing an embryonic plant.', 'If you plant a seed in the spring, you may have a pleasant surprise in the autumn.', 'Nature & Environment', 'hạt giống', 'Một noãn đã được thụ tinh và chín, chứa một cây phôi thai.', 'Nếu bạn gieo một hạt giống vào mùa xuân, bạn có thể có một bất ngờ thú vị vào mùa thu.'),
    ('0d945089-01f1-561d-a441-180e3e3bb6bf', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'shell', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ʃɛl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shell-us.mp3', 'A hard external covering of an animal.', 'The restaurant served caramelized onion shells.', 'Nature & Environment', 'vỏ', 'Lớp vỏ cứng bên ngoài của một con vật.', 'Nhà hàng phục vụ vỏ hành tây caramel.'),
    ('d584468e-cd91-500c-b8c4-2ee044c684ac', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'shine', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ʃaɪn/', 'audio/shine.mp3', 'Brightness from a source of light.', 'She''s certainly taken a shine to you.', 'Nature & Environment', 'tỏa sáng', 'Độ sáng từ một nguồn ánh sáng.', 'Cô ấy chắc chắn đã có cảm tình với bạn.'),
    ('445df361-d78d-5f53-9b5c-1386d6646f06', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'shoot', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ʃuːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shoot-uk.mp3', 'The emerging stem and embryonic leaves of a new plant.', 'The land shoots into a promontory.', 'Nature & Environment', 'chồi non', 'Thân cây mới nhú và lá mầm của một cây mới.', 'Vùng đất nhô ra thành một mũi đất.'),
    ('e453038b-f7a1-5eea-bfc4-3f36459acf55', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'soil', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/sɔɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/soil-us.mp3', 'A mixture of mineral particles and organic material, used to support plant growth.', 'Kenyan soil', 'Nature & Environment', 'đất', 'Hỗn hợp của các hạt khoáng chất và vật liệu hữu cơ, được dùng để hỗ trợ sự phát triển của thực vật.', 'Đất Kenya'),
    ('fd908cc8-5d30-5794-90f2-c4c727fde759', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'southern', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈsʌðɚn/', 'audio/southern.mp3', 'Someone from one of the states which seceded in 1861 and briefly formed the Confederate States of America, or, more broadly, from some neighboring states as well (but excluding geographically-southerly states like Arizona); compare the South.', 'The southern climate.', 'Nature & Environment', 'miền nam', 'Một người đến từ một trong các tiểu bang đã ly khai vào năm 1861 và tạm thời hình thành Liên minh các Tiểu bang Hoa Kỳ, hoặc, rộng hơn, từ một số tiểu bang lân cận (nhưng không bao gồm các bang cực nam về mặt địa lý).', 'Khí hậu miền nam.'),
    ('1d3e4029-fa28-513e-89fe-b62fb14b7cc1', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'tail', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/teɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tail-au.mp3', 'The caudal appendage of an animal that is attached to its posterior and near the anus.', 'Most primates have a tail and fangs.', 'Nature & Environment', 'cái đuôi', 'Phần phụ ở đuôi của một động vật, được gắn vào phía sau và gần hậu môn.', 'Hầu hết các loài linh trưởng đều có đuôi và răng nanh.'),
    ('3b92dd81-e5b5-592d-8c10-e87ec26ce150', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'waste', 'B1', '["n", "v", "adj"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}, {"pos": "adj", "level": "B1"}]'::jsonb, '/weɪst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/waste-us.mp3', 'Excess of material, useless by-products or damaged, unsaleable products; garbage; rubbish.', 'The cage was littered with animal waste', 'Nature & Environment', 'chất thải', 'Vật liệu dư thừa, sản phẩm phụ vô dụng hoặc sản phẩm bị hư hỏng, không bán được; rác; đồ phế thải.', 'Lồng chất đầy chất thải động vật'),
    ('237799c5-e514-5a7f-9275-d7ea614d367d', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'wing', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/wɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wing-us.mp3', 'An appendage of an animal''s (bird, bat, insect) body that enables it to fly; a similar fin at the side of a ray or similar fish', 'to take wing', 'Nature & Environment', 'cánh', 'Bộ phận phụ của cơ thể động vật (chim, dơi, côn trùng) cho phép nó bay; một vây tương tự ở bên cạnh của cá đuối hoặc cá tương tự.', 'cất cánh bay'),
    ('0a413eb9-e8bf-5d31-90ec-53abe765c14f', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'freeze', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ˈfɹiːz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/freeze-us.mp3', 'Especially of a liquid, to become solid due to low temperature.', 'The lake froze solid.', 'Weather & Climate', 'đóng băng', 'Đặc biệt là chất lỏng, trở nên rắn lại do nhiệt độ thấp.', 'Hồ đóng băng cứng.'),
    ('e62af61c-4c5e-5ef8-8c8b-68729c007464', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'atmosphere', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈæt.məsˌfɪə(ɹ)/', 'audio/atmosphere.mp3', 'The gases surrounding the Earth or any astronomical body.', NULL, 'Nature & Environment', 'khí quyển, bầu không khí', NULL, NULL),
    ('275733ce-b4f3-572e-8389-1bd2128b1cad', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'bee', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈbiː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bee-us.mp3', 'A flying insect, of the clade Anthophila within the hymenopteran superfamily Apoidea, known for its organised societies (though only a minority have them), for collecting pollen and (in some species) producing wax and honey.', NULL, 'Nature & Environment', 'con ong', 'Một loài côn trùng biết bay, thuộc nhánh Anthophila trong siêu họ ong bắp cày Apoidea, nổi tiếng với xã hội có tổ chức (mặc dù chỉ một số ít có), vì việc thu thập phấn hoa và (ở một số loài)', NULL),
    ('2367fc8e-d665-5af6-9ba4-2cb18d8b8c9b', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'earthquake', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɜːθkweɪk/', 'audio/earthquake.mp3', 'A shaking of the ground, caused by volcanic activity or movement around geologic faults.', NULL, 'Nature & Environment', 'động đất', 'Sự rung chuyển của mặt đất, gây ra bởi hoạt động núi lửa hoặc chuyển động xung quanh các đứt gãy địa chất.', NULL),
    ('aa596ba0-03d2-57c4-80b3-ac57d8361765', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'eastern', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈiːstən/', 'audio/eastern.mp3', 'Of, facing, situated in, or related to the east.', NULL, 'Nature & Environment', 'thuộc phía đông', 'Thuộc về, hướng về, nằm ở, hoặc liên quan đến phía đông.', NULL),
    ('3e3ff030-33ab-502e-88c5-b4e243f9a766', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'fur', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/fɜː(ɹ)/', 'audio/fur.mp3', 'The hairy coat of various mammal species, especially when fine, soft and thick.', NULL, 'Nature & Environment', 'lông thú', 'Bộ lông của các loài động vật có vú, đặc biệt khi mịn, mềm và dày.', NULL),
    ('2783af68-b62c-5415-81ce-e23fda8ce097', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'hurricane', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈhʌɹɪkən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hurricane-uk.mp3', 'A severe tropical cyclone in the North Atlantic Ocean, Caribbean Sea, Gulf of Mexico, or in the eastern North Pacific off the west coast of Mexico, with winds of 119 km/h (74 miles per hour) or greater accompanied by rain, lightning, and thunder that sometimes moves into temperate latitudes.', NULL, 'Weather & Climate', 'bão', 'Một cơn bão nhiệt đới nghiêm trọng ở Bắc Đại Tây Dương, Biển Caribe, Vịnh Mexico, hoặc ở phía đông Bắc Thái Bình Dương ngoài khơi bờ biển phía tây Mexico, với sức gió từ 119 km/h (74 dặm một giờ) trở lên.', NULL),
    ('d989846d-8716-574b-9120-49fde67c47e7', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'environmental', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, NULL, 'audio/environmental.mp3', 'Pertaining to the environment.', NULL, 'Nature & Environment', 'thuộc môi trường', 'Liên quan đến môi trường.', NULL),
    ('1b3a0fa8-6478-5a74-884d-2047426a3a94', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'bank (river)', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, NULL, 'audio/bank_(river).mp3', NULL, NULL, 'Nature & Environment', 'bờ sông', NULL, NULL),
    ('e30d3bc5-b9a8-51d7-afb0-4af08d8141fa', '811ae97c-7efa-51d5-ab66-83dfca31aa48', 'stick (piece of wood)', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, NULL, 'audio/stick_(piece_of_wood).mp3', NULL, NULL, 'Nature & Environment', 'que, gậy', NULL, NULL)
