INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('cd43f3fa-f337-532a-83ec-b3dc8eeaebde', '143410ca-7060-5a4c-9f5f-d314d6035968', 'access', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈæksɛs/', 'audio/access.mp3', 'A way or means of approaching or entering; an entrance; a passage.', 'an access of territory', 'Technology & Media', 'truy cập', 'Một cách hoặc phương tiện tiếp cận hoặc đi vào; lối vào; lối đi.', 'việc mở rộng lãnh thổ'),
    ('564094ad-253a-5b27-a800-8da42661ed26', '143410ca-7060-5a4c-9f5f-d314d6035968', 'battery', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈbætəɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/battery-uk.mp3', 'A device used to power electric devices, consisting of a set of electrically connected electrochemical or, archaically, electrostatic cells. A single such cell when used by itself.', 'Schoolchildren take a battery of standard tests to measure their progress.', 'Technology & Media', 'pin, ắc quy', 'Một thiết bị dùng để cấp nguồn cho các thiết bị điện, bao gồm một bộ pin điện hóa hoặc, theo cách cổ điển, pin tĩnh điện được kết nối với nhau. Một tế bào đơn lẻ như vậy khi được sử dụng riêng lẻ.', 'Học sinh thực hiện một loạt các bài kiểm tra tiêu chuẩn để đo lường sự tiến bộ của chúng.'),
    ('407ee7ba-b8bf-592a-a980-2c58afd4fd0f', '143410ca-7060-5a4c-9f5f-d314d6035968', 'channel', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈtʃænəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/channel-us.mp3', 'The physical confine of a river or slough, consisting of a bed and banks.', 'The water coming out of the waterwheel created a standing wave in the channel.', 'Technology & Media', 'kênh', 'Ranh giới vật lý của một con sông hoặc lạch nước, bao gồm lòng sông và bờ.', 'Nước chảy ra từ bánh xe nước tạo ra một con sóng đứng trong lòng kênh.'),
    ('7bc34f90-8b34-5d8e-b1f2-b49d4076bc5f', '143410ca-7060-5a4c-9f5f-d314d6035968', 'click', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/klɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/click-uk.mp3', 'A brief, sharp, not particularly loud, relatively high-pitched sound produced by the impact of something small and hard against something hard, such as by the operation of a switch, a lock or a latch, or a finger pressed against the thumb and then released to strike the hand.', 'I turned the key, the lock gave a click and the door opened; a click of one’s fingers', 'Technology & Media', 'nhấp chuột, tiếng click', 'Một âm thanh ngắn, sắc, không đặc biệt lớn, tương đối cao, được tạo ra bởi tác động của một thứ gì đó nhỏ và cứng vào một thứ cứng, chẳng hạn như do hoạt động của công tắc, khóa hoặc chốt.', 'Tôi xoay chìa khóa, ổ khóa phát ra tiếng click và cánh cửa mở ra; một cái búng tay'),
    ('f14f2afc-af3a-5bb2-9a16-22527627aa0c', '143410ca-7060-5a4c-9f5f-d314d6035968', 'connection', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/kəˈnɛkʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/connection-us.mp3', 'The act of connecting.', 'My headache has no connection with me going out last night.', 'Technology & Media', 'sự kết nối', 'Hành động kết nối.', 'Cơn đau đầu của tôi không có liên quan gì đến việc tôi đi chơi tối qua.'),
    ('031070e0-e9df-591d-bbd1-6b85af8f5b8f', '143410ca-7060-5a4c-9f5f-d314d6035968', 'editor', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɛdɪtə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/editor-uk.mp3', 'A person who edits or makes changes to documents.', 'John Johnson wrote this term paper and the editor was Joan Johnson.', 'Technology & Media', 'biên tập viên', 'Một người biên tập hoặc thay đổi tài liệu.', 'John Johnson viết bài tiểu luận học kỳ này và biên tập viên là Joan Johnson.'),
    ('71d318ab-6c61-5ed8-aba0-ecb29ef7478d', '143410ca-7060-5a4c-9f5f-d314d6035968', 'file', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/faɪl/', 'audio/file.mp3', 'A collection of papers collated and archived together.', 'I''m going to delete these unwanted files to free up some disk space.', 'Technology & Media', 'tập tin, hồ sơ', 'Một bộ sưu tập giấy tờ được tập hợp và lưu trữ cùng nhau.', 'Tôi sẽ xóa những tập tin không mong muốn này để giải phóng một số dung lượng đĩa.'),
    ('aa5a20bc-17ce-50dc-8873-2851dd7b4375', '143410ca-7060-5a4c-9f5f-d314d6035968', 'fuel', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈfjuːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fuel-uk.mp3', 'Substance consumed to provide energy through combustion, or through chemical or nuclear reaction.', 'His books were fuel for the revolution.', 'Technology & Media', 'nhiên liệu', 'Chất được tiêu thụ để cung cấp năng lượng thông qua quá trình đốt cháy, hoặc phản ứng hóa học hoặc hạt nhân.', 'Những cuốn sách của ông là nhiên liệu cho cuộc cách mạng.'),
    ('90830c46-4a6c-51e6-a759-1b02416fcff1', '143410ca-7060-5a4c-9f5f-d314d6035968', 'headline', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈhɛd.laɪn/', 'audio/headline.mp3', 'The heading or title of a magazine or newspaper article.', 'The headline on today''s newspaper reads "John Doe Wins Wood-Splitting Competition."', 'Technology & Media', 'tiêu đề', 'Phần tiêu đề hoặc tên của một bài báo trên tạp chí hoặc báo.', 'Tiêu đề trên tờ báo hôm nay viết "John Doe Thắng Cuộc Thi Chẻ Củi."'),
    ('38ac29ac-6bcb-5d9f-b127-4d772585f421', '143410ca-7060-5a4c-9f5f-d314d6035968', 'keyboard', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkiːbɔːd/', 'audio/keyboard.mp3', '(etc.) A set of keys used to operate a typewriter, computer etc.', 'Keyboarding is the part of this job I hate the most.', 'Technology & Media', 'bàn phím', '(v.v.) Một bộ phím dùng để vận hành máy chữ, máy tính, v.v.', 'Đánh máy là phần tôi ghét nhất trong công việc này.'),
    ('2793694d-0c34-53e8-b572-4082c5bee21a', '143410ca-7060-5a4c-9f5f-d314d6035968', 'press', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, '/pɹɛs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/press-uk.mp3', 'A device used to apply pressure to an item.', 'a flower press', 'Technology & Media', 'báo chí', 'Thiết bị dùng để tạo áp lực lên một vật.', 'máy ép hoa'),
    ('88e686a7-2f54-5df4-a83a-07924192e092', '143410ca-7060-5a4c-9f5f-d314d6035968', 'printing', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpɹɪntɪŋ/', 'audio/printing.mp3', 'To produce one or more copies of a text or image on a surface, especially by machine; often used with out or off: print out, print off.', 'Print the draft double-spaced so we can mark changes between the lines.', 'Technology & Media', 'việc in ấn', 'Tạo ra một hoặc nhiều bản sao của văn bản hoặc hình ảnh trên một bề mặt, đặc biệt bằng máy; thường dùng với out hoặc off: in ra, in ra.', 'In bản nháp cách dòng đôi để chúng ta có thể đánh dấu các thay đổi giữa các dòng.'),
    ('5666addc-b892-545e-a653-3b58238a5bce', '143410ca-7060-5a4c-9f5f-d314d6035968', 'remote', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '[ɹəˈməʊt]', 'audio/remote.mp3', 'An element of broadcast programming originating away from the station''s or show''s control room.', 'A remote operator may control the vehicle with a wireless handset.', 'Technology & Media', 'từ xa', 'Một yếu tố của chương trình phát sóng có nguồn gốc từ xa phòng điều khiển của đài hoặc chương trình.', 'Một người điều khiển từ xa có thể kiểm soát phương tiện bằng tay cầm không dây.'),
    ('ef5caeb7-812b-5f75-b09d-8f5150acef3e', '143410ca-7060-5a4c-9f5f-d314d6035968', 'scan', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/skæn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/scan-us.mp3', 'Close investigation.', 'The operators vacated the room during the scan.', 'Technology & Media', 'quét', 'Điều tra kỹ lưỡng.', 'Các nhân viên đã rời khỏi phòng trong quá trình quét.'),
    ('139cb272-ad95-5636-abb0-98ce054dc77b', '143410ca-7060-5a4c-9f5f-d314d6035968', 'signal', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈsɪɡnəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/signal-us.mp3', 'A sequence of states representing an encoded message in a communication channel.', 'My mobile phone can''t get a signal in the railway station.', 'Technology & Media', 'tín hiệu', 'Một chuỗi trạng thái biểu thị một thông điệp được mã hóa trong một kênh truyền thông.', 'Điện thoại di động của tôi không bắt được tín hiệu trong nhà ga.'),
    ('bb2c95e3-00e5-5c5f-ae6d-d0c7a6e4490e', '143410ca-7060-5a4c-9f5f-d314d6035968', 'switch', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/swɪtʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/switch-us.mp3', 'A bundle of thin sticks, typically made of wood, sometimes bond in such a way that binding can be moved so that it varies the tightness of the binding.', 'Use the /b switch to specify black-and-white printing.', 'Technology & Media', 'công tắc, chuyển đổi', 'Một bó que mỏng, thường làm bằng gỗ, đôi khi được buộc theo cách mà chỗ buộc có thể di chuyển để thay đổi độ chặt của chỗ buộc.', 'Sử dụng công tắc /b để chỉ định in trắng đen.'),
    ('de9b9a59-5951-5466-aa90-451a6c6d42bd', '143410ca-7060-5a4c-9f5f-d314d6035968', 'arrival', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/əˈɹaɪ.vəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/arrival-uk.mp3', 'The act of arriving or something that has arrived.', 'The early arrival of the bride created a stir.', 'Travel & Transport', 'sự đến', 'Hành động đến nơi hoặc thứ gì đó đã đến.', 'Việc cô dâu đến sớm đã tạo nên một sự xôn xao.'),
    ('c2d631ce-7585-5a6b-afb4-bb1dcc0ea6c5', '143410ca-7060-5a4c-9f5f-d314d6035968', 'departure', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/dɪˈpɑː(ɹ)tjə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/departure-uk.mp3', 'The act of departing or something that has departed.', 'The departure was scheduled for noon.', 'Travel & Transport', 'sự khởi hành', 'Hành động khởi hành hoặc một cái gì đó đã khởi hành.', 'Chuyến khởi hành được lên lịch vào buổi trưa.'),
    ('ff38f06b-ae02-5225-8e57-b128c1b85eb0', '143410ca-7060-5a4c-9f5f-d314d6035968', 'expedition', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɛkspəˈdɪʃən/', 'audio/expedition.mp3', 'The act of expediting something; prompt execution.', 'a naval expedition', 'Travel & Transport', 'cuộc thám hiểm', 'Hành động thúc đẩy việc gì đó; thực hiện nhanh chóng.', 'một cuộc thám hiểm hải quân'),
    ('497cf3de-1ce2-5578-8b29-449e22de0dff', '143410ca-7060-5a4c-9f5f-d314d6035968', 'helicopter', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈheliˌkɔptə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/helicopter-au.mp3', 'An aircraft that is borne along by one or more sets of long rotating blades which allow it to hover, move in any direction including reverse, or land; and typically having a smaller set of blades on its tail that stabilize the aircraft.', 'We flew over the city in a helicopter.', 'Travel & Transport', 'máy bay trực thăng', 'Một loại máy bay được đẩy đi bởi một hoặc nhiều bộ cánh quay dài cho phép nó lơ lửng, di chuyển theo mọi hướng kể cả lùi, hoặc hạ cánh; và thường có một bộ cánh quay nhỏ hơn trên đó.', 'Chúng tôi bay qua thành phố bằng máy bay trực thăng.'),
    ('2eccdc7c-eace-5265-91df-b2344791fb88', '143410ca-7060-5a4c-9f5f-d314d6035968', 'locate', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/ləʊˈkeɪt/', 'audio/locate.mp3', 'To place; to set in a particular spot or position.', 'The council must locate the new hospital', 'Travel & Transport', 'xác định vị trí', 'Đặt; đặt ở một vị trí hoặc địa điểm cụ thể.', 'Hội đồng phải xác định vị trí cho bệnh viện mới'),
    ('8645c656-2831-5e57-aeae-795b2beb61e7', '143410ca-7060-5a4c-9f5f-d314d6035968', 'located', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ləʊˈkeɪtɪd/', 'audio/located.mp3', 'To place; to set in a particular spot or position.', 'The council must locate the new hospital', 'Travel & Transport', 'nằm ở', 'Đặt; đặt ở một vị trí hoặc địa điểm cụ thể.', 'Hội đồng phải xác định vị trí cho bệnh viện mới'),
    ('8597e700-e567-5cff-a6e6-ddd1d45b3e78', '143410ca-7060-5a4c-9f5f-d314d6035968', 'port', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/pɔːt/', 'audio/port.mp3', 'A place on the coast at which ships can shelter, or dock to load and unload cargo or passengers.', 'Each eight has four ports and four starboards.', 'Travel & Transport', 'cảng', 'Một nơi trên bờ biển nơi tàu thuyền có thể trú ẩn, hoặc cập bến để bốc dỡ hàng hóa hoặc hành khách.', 'Mỗi nhóm tám người có bốn mạn trái và bốn mạn phải.'),
    ('ff3c489f-ad50-56d4-8b89-496fcdeeae52', '143410ca-7060-5a4c-9f5f-d314d6035968', 'reservation', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˌɹɛzəˈveɪʃən/', 'audio/reservation.mp3', 'The act of reserving, withholding or keeping back.', 'The committee authorised the reservation of funds.', 'Travel & Transport', 'đặt chỗ', 'Hành động đặt trước, giữ lại hoặc không đưa ra.', 'Ủy ban đã ủy quyền việc dành riêng quỹ.'),
    ('98d6111f-4ad4-5b8d-8326-f625cc88ff27', '143410ca-7060-5a4c-9f5f-d314d6035968', 'tent', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/tɛnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tent-us.mp3', 'A pavilion or portable lodge consisting of skins, canvas, or some strong cloth, stretched and sustained by poles, used for sheltering people from the weather.', 'We were camping in a three-man tent.', 'Travel & Transport', 'lều', 'Một kiến trúc di động hoặc lều gồm da, vải bạt, hoặc vải chắc chắn, được căng và giữ bởi các cọc, dùng để che chở con người khỏi thời tiết.', 'Chúng tôi đang cắm trại trong một chiếc lều ba người.'),
    ('ee58d6cc-967c-58ce-acf3-e3c93093673b', '143410ca-7060-5a4c-9f5f-d314d6035968', 'afford', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/əˈfɔːd/', 'audio/afford.mp3', 'To incur, stand, or bear without serious detriment, as an act which might under other circumstances be injurious;—with an auxiliary, as can, could, might, etc.; to be able or rich enough.', 'I think we can afford the extra hour it will take. We can only afford to buy a small car at the moment.', 'Shopping & Money', 'có đủ khả năng', 'Chịu đựng, chịu được, hoặc gánh vác mà không gây tổn hại nghiêm trọng, như một hành động mà trong hoàn cảnh khác có thể gây hại;—với trợ động từ, như can, could, might, v.v.; có khả năng hoặc đủ giàu.', 'Tôi nghĩ chúng ta có thể dành thêm một giờ nữa. Hiện tại chúng ta chỉ có đủ khả năng mua một chiếc xe hơi nhỏ.'),
    ('3ee9efd9-ad1f-5911-a009-2a0b6e4b89e2', '143410ca-7060-5a4c-9f5f-d314d6035968', 'charge', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/t͡ʃɑːd͡ʒ/', 'audio/charge.mp3', 'The amount of money levied for a service.', 'There will be a charge of five dollars.', 'Shopping & Money', 'phí', 'Số tiền được tính cho một dịch vụ.', 'Sẽ có một khoản phí là năm đô la.'),
    ('ea4921cd-44ef-5562-91fa-b4f309f797c5', '143410ca-7060-5a4c-9f5f-d314d6035968', 'coin', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/kɔɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/coin-us.mp3', '(money) A piece of currency, usually metallic and in the shape of a disc, but sometimes polygonal, or with a hole in the middle.', 'She spent some serious coin on that car!', 'Shopping & Money', 'đồng xu', '(tiền) Một đơn vị tiền tệ, thường bằng kim loại và có hình dạng đĩa, nhưng đôi khi đa giác, hoặc có lỗ ở giữa.', 'Cô ấy đã tiêu một khoản tiền lớn cho chiếc xe đó!'),
    ('c470639c-7bde-576f-b094-448ddf318b9e', '143410ca-7060-5a4c-9f5f-d314d6035968', 'collection', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/kəˈlɛkʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/collection-us.mp3', 'A set of items or amount of material procured or gathered together.', 'The asteroid belt consists of a collection of dust, rubble, and minor planets.', 'Shopping & Money', 'bộ sưu tập', 'Một tập hợp các vật phẩm hoặc lượng vật liệu được thu thập hoặc gom lại với nhau.', 'Vành đai tiểu hành tinh bao gồm một tập hợp bụi, đá vụn và các hành tinh nhỏ.'),
    ('3ea48e29-0cb1-58f8-9fcf-a9299280bfd1', '143410ca-7060-5a4c-9f5f-d314d6035968', 'currency', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈkʌɹ.ən.si/', 'audio/currency.mp3', 'Money or other items used to facilitate transactions.', 'Wampum was used as a currency by Amerindians.', 'Shopping & Money', 'tiền tệ', 'Tiền hoặc các vật phẩm khác được sử dụng để tạo điều kiện cho giao dịch.', 'Wampum được người Mỹ bản địa sử dụng như một loại tiền tệ.'),
    ('25421763-891a-56e2-a4bb-e0b2b13da75a', '143410ca-7060-5a4c-9f5f-d314d6035968', 'deliver', 'B1', '["v"]'::jsonb, '[{"pos": "v", "level": "B1"}]'::jsonb, '/dɪˈlɪvə(ɹ)/', 'audio/deliver.mp3', 'To set free from restraint or danger.', 'deliver a captive from the prison', 'Shopping & Money', 'giao hàng', 'Giải phóng khỏi sự kiềm chế hoặc nguy hiểm.', 'giải cứu một tù nhân khỏi nhà tù'),
    ('100dcb44-c5bb-5580-8c03-2e98763880a1', '143410ca-7060-5a4c-9f5f-d314d6035968', 'discount', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/dɪsˈkaʊnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/discount-uk.mp3', 'A reduction in price.', 'This store offers discounts on all its wares. That store specializes in discount wares, too.', 'Shopping & Money', 'giảm giá', 'Một khoản giảm giá.', 'Cửa hàng này cung cấp giảm giá cho tất cả hàng hóa. Cửa hàng đó cũng chuyên về hàng hóa giảm giá.'),
    ('251947ae-960c-57cc-8aeb-7b42501db383', '143410ca-7060-5a4c-9f5f-d314d6035968', 'goods', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɡʊdz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/goods-us.mp3', 'The forces or behaviours that are the enemy of evil. Usually consists of helping others and general benevolence.', 'The best is the enemy of the good.', 'Shopping & Money', 'hàng hóa', 'Những lực lượng hoặc hành vi là kẻ thù của cái ác. Thường bao gồm việc giúp đỡ người khác và lòng nhân ái nói chung.', 'Cái tốt nhất là kẻ thù của cái tốt.'),
    ('bf373275-614b-5c8e-bcb3-03d9878e80c0', '143410ca-7060-5a4c-9f5f-d314d6035968', 'label', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈleɪbəl/', 'audio/label.mp3', 'A small ticket or sign giving information about something to which it is attached or intended to be attached.', 'Although the label priced this poster at three pounds, I got it for two.', 'Shopping & Money', 'nhãn mác', 'Một tấm vé hoặc biển nhỏ cung cấp thông tin về thứ mà nó được gắn vào hoặc dự định gắn vào.', 'Mặc dù nhãn giá của tấm áp phích này là ba bảng, tôi đã mua nó với giá hai bảng.'),
    ('45583727-6881-5a0a-9fb4-c857f00293af', '143410ca-7060-5a4c-9f5f-d314d6035968', 'leather', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈlɛðə/', 'audio/leather.mp3', 'A tough material produced from the skin of animals, by tanning or similar process, used e.g. for clothing.', 'He leathered the ball all the way down the street.', 'Shopping & Money', 'da thuộc', 'Một chất liệu bền được sản xuất từ da động vật, bằng quá trình thuộc da hoặc tương tự, được sử dụng ví dụ cho quần áo.', 'Anh ấy đá quả bóng bằng da xuống tận cuối phố.'),
    ('ae858f4a-f375-5860-96fd-1ba03f125e19', '143410ca-7060-5a4c-9f5f-d314d6035968', 'package', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈpækɪdʒ/', 'audio/package.mp3', 'Something which is packed, a parcel, a box, an envelope.', 'Did you test the software package to ensure completeness?', 'Shopping & Money', 'gói hàng', 'Một thứ được đóng gói, một bưu kiện, một cái hộp, một phong bì.', 'Bạn đã kiểm tra gói phần mềm để đảm bảo tính đầy đủ chưa?'),
    ('7f569ba5-a722-51b9-ab6e-fa80848855ad', '143410ca-7060-5a4c-9f5f-d314d6035968', 'receipt', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ɹɪˈsiːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/receipt-us.mp3', 'The act of receiving, or the fact of having been received.', 'A balance payable on receipt of the goods.', 'Shopping & Money', 'biên lai', 'Hành động nhận, hoặc việc đã được nhận.', 'Số dư phải trả khi nhận hàng.'),
    ('a8e4662b-9dd9-57ec-a04e-e26f32f42f35', '143410ca-7060-5a4c-9f5f-d314d6035968', 'rent', 'B1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B1"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ɹɛnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rent-uk.mp3', 'A payment made by a tenant at intervals in order to occupy a property.', 'A New York city taxicab license earns more than $10,000 a year in rent.', 'Shopping & Money', 'tiền thuê', 'Khoản thanh toán được thực hiện bởi người thuê theo định kỳ để chiếm dụng một tài sản.', 'Một giấy phép taxi thành phố New York kiếm được hơn 10.000 đô la một năm tiền thuê.'),
    ('ba450d08-c03d-56d4-9b49-fe854dbb61c5', '143410ca-7060-5a4c-9f5f-d314d6035968', 'spending', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈspɛndɪŋ/', 'audio/spending.mp3', 'Present participle of spend, expenditure.', 'excessive spendings', 'Shopping & Money', 'chi tiêu', 'Hiện tại phân từ của spend, sự chi tiêu.', 'chi tiêu quá mức'),
    ('9fcc76ea-df62-5ef1-9aac-f6c38da9dd20', '143410ca-7060-5a4c-9f5f-d314d6035968', 'valuable', 'B1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B1"}]'::jsonb, '/ˈvæljuəbl̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/valuable-us.mp3', 'A personal possession such as jewellery, of relatively great monetary value; — usually used in plural form.', 'valuable gemstones', 'Shopping & Money', 'có giá trị', 'Tài sản cá nhân như trang sức, có giá trị tiền tệ tương đối lớn; — thường được dùng ở dạng số nhiều.', 'đá quý có giá trị'),
    ('97742c9b-161d-5eb2-b0a2-c061b90537a5', '143410ca-7060-5a4c-9f5f-d314d6035968', 'update', 'B1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B1"}, {"pos": "n", "level": "B1"}]'::jsonb, NULL, 'audio/update.mp3', 'An advisement providing more up-to-date information than currently known.', 'He gave me an update on the situation in New York.', 'Technology & Media', 'cập nhật', 'Thông báo cung cấp thông tin mới hơn so với hiện tại.', 'Anh ấy cho tôi một bản cập nhật về tình hình ở New York.'),
    ('1389a2a9-ef4a-506e-8b49-991ea83029ff', '143410ca-7060-5a4c-9f5f-d314d6035968', 'robot', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈɹoʊbət/', 'https://api.dictionaryapi.dev/media/pronunciations/en/robot-au.mp3', 'A machine built to carry out some complex task or group of tasks by physically moving, especially one which can be programmed.', NULL, 'Technology & Media', 'người máy', 'Một cỗ máy được chế tạo để thực hiện một số nhiệm vụ phức tạp hoặc nhóm nhiệm vụ bằng cách di chuyển vật lý, đặc biệt là loại có thể được lập trình.', NULL),
    ('45838e17-6d32-5cb5-8328-7b3ed68555c2', '143410ca-7060-5a4c-9f5f-d314d6035968', 'software', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈsɑftˌwɛɹ/', 'audio/software.mp3', 'Encoded computer instructions, usually modifiable (unless stored in some form of unalterable memory such as ROM).', NULL, 'Technology & Media', 'phần mềm', 'Các chỉ dẫn máy tính được mã hóa, thường có thể sửa đổi (trừ khi được lưu trữ trong một số dạng bộ nhớ không thể thay đổi như ROM).', NULL),
    ('b67fc104-45fb-5fcc-be53-71c5a0babccb', '143410ca-7060-5a4c-9f5f-d314d6035968', 'accommodation', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ə.ˌkɒm.ə.ˈdeɪ.ʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/accommodation-uk.mp3', '(usually a mass noun) Lodging in a dwelling or similar living quarters afforded to travellers in hotels or on cruise ships, or prisoners, etc.', NULL, 'Travel & Transport', 'chỗ ở', '(thường là danh từ không đếm được) Chỗ ở trong một ngôi nhà hoặc khu sinh hoạt tương tự dành cho khách du lịch trong khách sạn hoặc trên tàu du lịch, hoặc tù nhân, v.v.', NULL),
    ('07dcfa1b-8d1e-5896-beb7-e913b92300b0', '143410ca-7060-5a4c-9f5f-d314d6035968', 'destination', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/dɛstɪˈneɪʃən/', 'audio/destination.mp3', 'The act of destining or appointing.', NULL, 'Travel & Transport', 'điểm đến', 'Hành động định mệnh hoặc chỉ định.', NULL),
    ('f58a0581-87c7-55d4-8dfc-0e50003714ab', '143410ca-7060-5a4c-9f5f-d314d6035968', 'location', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ləʊˈkeɪʃən/', 'audio/location.mp3', 'A particular point or place in physical space.', NULL, 'Travel & Transport', 'địa điểm', 'Một điểm hoặc nơi cụ thể trong không gian vật lý.', NULL),
    ('914a4cf7-6248-50da-abc3-2fbb666bc0d4', '143410ca-7060-5a4c-9f5f-d314d6035968', 'tyre', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/taɪə(ɹ)/', 'audio/tyre.mp3', 'The ring-shaped protective covering around a wheel which is usually made of rubber or plastic composite and is either pneumatic or solid.', NULL, 'Travel & Transport', 'lốp xe', 'Lớp bảo vệ hình vòng quanh bánh xe thường được làm bằng cao su hoặc composite nhựa và có thể là lốp hơi hoặc đặc.', NULL),
    ('45c2c516-16b6-55df-a9d2-94f791654517', '143410ca-7060-5a4c-9f5f-d314d6035968', 'mall', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/mɔːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mall-au.mp3', 'A pedestrianised street, especially a shopping precinct.', NULL, 'Shopping & Money', 'trung tâm mua sắm', 'Một con phố dành cho người đi bộ, đặc biệt là khu mua sắm.', NULL),
    ('538a3489-08d5-5571-8730-7ce3bb08167a', '143410ca-7060-5a4c-9f5f-d314d6035968', 'payment', 'B1', '["n"]'::jsonb, '[{"pos": "n", "level": "B1"}]'::jsonb, '/ˈpeɪmənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/payment-us.mp3', 'The act of paying.', NULL, 'Shopping & Money', 'sự thanh toán', 'Hành động trả tiền.', NULL)
